def _transport_host_gmres_progress_every() -> int:
    env = os.environ.get("SFINCS_JAX_TRANSPORT_HOST_GMRES_PROGRESS_EVERY", "").strip()
    try:
        return max(0, int(env)) if env else 10
    except ValueError:
        return 10


