def _rhs1_qi_device_probe_uses_minres_step() -> bool:
    """Return whether QI-device seed probes should line-search each correction."""

    raw = (
        os.environ.get(
            "SFINCS_JAX_RHSMODE1_XBLOCK_PC_QI_DEVICE_PRECONDITIONER_STEP_POLICY",
            "fixed",
        )
        .strip()
        .lower()
        .replace("-", "_")
    )
    return raw in {"minres", "residual_minimizing", "line_search", "linesearch"}


def _rhs1_xblock_fallback_initial_guess(
    *,
    candidate: np.ndarray,
    original_x0: jnp.ndarray | None,
    rhs_shape: tuple[int, ...],
    candidate_residual_norm: float,
    rhs_norm: float,
    precondition_side: str,
) -> tuple[jnp.ndarray | None, bool, bool]:
    """Return the safe GMRES fallback initial guess for x-block Krylov rescues.

    Non-GMRES host Krylov methods may produce a useful physical-space state
    before failing the strict true-residual gate. Reusing that state is safe for
    left/no preconditioning when it improves over the zero-state RHS norm. It is
    deliberately disabled for right preconditioning because SciPy's right-PC
    iteration state lives in preconditioned coordinates.
    """
    candidate_improved_rhs = bool(
        np.isfinite(float(candidate_residual_norm))
        and np.isfinite(float(rhs_norm))
        and float(candidate_residual_norm) < float(rhs_norm)
    )
    if (not candidate_improved_rhs) or str(precondition_side).strip().lower() == "right":
        return original_x0, False, candidate_improved_rhs
    try:
        candidate_x0 = jnp.asarray(candidate, dtype=jnp.float64)
        if candidate_x0.shape == tuple(rhs_shape) and bool(jnp.all(jnp.isfinite(candidate_x0))):
            return candidate_x0, True, candidate_improved_rhs
    except Exception:
        pass
    return original_x0, False, candidate_improved_rhs


def _rhs1_xblock_post_coarse_directions(
    *,
    op: V3FullSystemOperator,
    residual: jnp.ndarray,
    preconditioner: Callable[[jnp.ndarray], jnp.ndarray],
    direction_projector: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expected_size: int | None = None,
    include_raw: bool,
    fsavg_lmax: int,
    max_extra_units: int,
    max_directions: int,
    angular_lmax: int = -1,
    include_angular_residual: bool = False,
) -> tuple[tuple[str, jnp.ndarray], ...]:
    """Build a small physics-aware correction basis for stalled RHSMode=1 solves.

    The basis is intentionally low-dimensional and matrix-free: residual-like
    directions handle generic error, flux-surface-averaged low-L modes target
    moment/nullspace drift, low Fourier angular modes target global coupling
    missed by an x-local inverse, residual-weighted angular/radial projections
    capture Fourier error with x-dependent amplitudes, and source/constraint
    directions target the constraint rows that are not visible to a pure x-block
    preconditioner.
    """
    residual = jnp.asarray(residual, dtype=jnp.float64)
    total = int(op.total_size)
    expected_size_use = total if expected_size is None else int(expected_size)
    directions: list[tuple[str, jnp.ndarray]] = []

    def _add(name: str, direction: jnp.ndarray) -> None:
        if len(directions) >= int(max_directions):
            return
        vec = jnp.asarray(direction, dtype=jnp.float64).reshape((-1,))
        if vec.shape != (total,):
            return
        if direction_projector is not None:
            vec = jnp.asarray(direction_projector(vec), dtype=jnp.float64).reshape((-1,))
        if vec.shape != (expected_size_use,):
            return
        try:
            norm = float(jnp.linalg.norm(vec))
        except Exception:
            return
        if np.isfinite(norm) and norm > 0.0:
            directions.append((str(name), vec))

    try:
        _add("preconditioned_residual", preconditioner(residual))
    except Exception:
        pass
    if include_raw:
        _add("raw_residual", residual)

    f_res = residual[: op.f_size].reshape(op.fblock.f_shape)
    factor = _fs_average_factor(op.theta_weights, op.zeta_weights, op.d_hat)
    lmax_use = min(max(0, int(fsavg_lmax)), max(0, int(op.n_xi) - 1))
    for il in range(lmax_use + 1):
        if len(directions) >= int(max_directions):
            break
        avg = jnp.einsum("tz,sxtz->sx", factor, f_res[:, :, il, :, :])
        f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
        f_dir = f_dir.at[:, :, il, :, :].set(avg[:, :, None, None])
        tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
        _add(f"fsavg_l{il}", jnp.concatenate([f_dir.reshape((-1,)), tail]))

    angular_l_use = min(int(angular_lmax), max(0, int(op.n_xi) - 1))
    if angular_l_use >= 0 and int(op.n_theta) > 1 and int(op.n_zeta) > 1:
        theta = jnp.arange(int(op.n_theta), dtype=jnp.float64)
        zeta = jnp.arange(int(op.n_zeta), dtype=jnp.float64)
        two_pi = float(2.0 * np.pi)
        mode_pairs = ((1, 0), (0, 1), (1, 1), (1, -1), (2, 0), (0, 2), (2, 1), (1, 2))
        for il in range(angular_l_use + 1):
            for m_mode, n_mode in mode_pairs:
                if len(directions) >= int(max_directions):
                    break
                phase = two_pi * (
                    float(m_mode) * theta[:, None] / float(max(1, int(op.n_theta)))
                    + float(n_mode) * zeta[None, :] / float(max(1, int(op.n_zeta)))
                )
                for parity, pattern in (("cos", jnp.cos(phase)), ("sin", jnp.sin(phase))):
                    pattern_norm = float(jnp.linalg.norm(pattern))
                    if (not np.isfinite(pattern_norm)) or pattern_norm <= 0.0:
                        continue
                    pattern = pattern / pattern_norm
                    if include_angular_residual:
                        weighted_pattern = factor * pattern
                        denom = float(jnp.sum(weighted_pattern * pattern))
                        if np.isfinite(denom) and abs(denom) > 0.0:
                            for s in range(int(op.n_species)):
                                if len(directions) >= int(max_directions):
                                    break
                                coeff = (
                                    jnp.einsum(
                                        "tz,xtz->x",
                                        weighted_pattern,
                                        f_res[s, :, il, :, :],
                                    )
                                    / float(denom)
                                )
                                f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
                                f_dir = f_dir.at[s, :, il, :, :].set(coeff[:, None, None] * pattern[None, :, :])
                                tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
                                _add(
                                    f"angular_residual_s{s}_l{il}_m{m_mode}_n{n_mode}_{parity}",
                                    jnp.concatenate([f_dir.reshape((-1,)), tail]),
                                )
                    for s in range(int(op.n_species)):
                        if len(directions) >= int(max_directions):
                            break
                        f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
                        f_dir = f_dir.at[s, :, il, :, :].set(pattern[None, :, :])
                        tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
                        _add(
                            f"angular_s{s}_allx_l{il}_m{m_mode}_n{n_mode}_{parity}",
                            jnp.concatenate([f_dir.reshape((-1,)), tail]),
                        )

    extra_start = int(op.f_size + op.phi1_size)
    extra_size = int(op.extra_size)
    if extra_size > 0 and len(directions) < int(max_directions):
        extra_res = residual[extra_start : extra_start + extra_size]
        extra_dir = jnp.zeros((total,), dtype=jnp.float64).at[extra_start : extra_start + extra_size].set(extra_res)
        _add("extra_residual", extra_dir)
        if extra_size <= int(max_extra_units):
            for ie in range(extra_size):
                if len(directions) >= int(max_directions):
                    break
                unit = jnp.zeros((total,), dtype=jnp.float64).at[extra_start + ie].set(1.0)
                _add(f"extra_unit_{ie}", unit)

    if int(op.constraint_scheme) == 1 and len(directions) < int(max_directions):
        ix0 = _ix_min(bool(op.point_at_x0))
        source_basis = _source_basis_constraint_scheme_1(op.x)
        for s in range(int(op.n_species)):
            for ibasis, basis in enumerate(source_basis):
                if len(directions) >= int(max_directions):
                    break
                f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
                f_dir = f_dir.at[s, ix0:, 0, :, :].set(basis[ix0:, None, None])
                tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
                full = jnp.concatenate([f_dir.reshape((-1,)), tail])
                _add(f"constraint1_source_s{s}_{ibasis}", full)

    return tuple(directions)


def _rhs1_xblock_qi_coarse_basis(
    *,
    op: V3FullSystemOperator,
    active_dof: bool,
    linear_size: int,
    max_rank: int,
    rank_rtol: float,
    include_angular: bool,
    include_blocks: bool,
    basis_kind: str = "legacy",
    max_candidates: int = 96,
    max_angular_mode: int = 2,
    include_radial: bool = True,
    include_radial_angular: bool = True,
    include_constraint_moments: bool = True,
    include_schur: bool = True,
) -> RHS1QICoarseBasis:
    """Build a padded QI coarse basis in the current x-block Krylov space.

    ``basis_kind='enriched'`` is intended for A/B testing the hard QI seed lane.  It adds
    radial moments, angular harmonics, constraint-like moments, and local
    block-Schur contrast vectors before rank truncation.  The legacy basis is
    still available for A/B tests and reproducibility.
    """
    n_species = int(op.n_species)
    n_x = int(op.n_x)
    n_l = int(op.n_xi)
    n_theta = int(op.n_theta)
    n_zeta = int(op.n_zeta)
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    block_sizes: list[int] = []
    block_x: list[int] = []
    block_species: list[int] = []
    for s in range(n_species):
        for ix in range(n_x):
            n_lx = int(nxi_for_x[ix]) if bool(active_dof) else n_l
            size = int(max(0, n_lx) * n_theta * n_zeta)
            if size <= 0:
                continue
            block_sizes.append(size)
            block_x.append(ix)
            block_species.append(s)
    if not block_sizes:
        raise RuntimeError("QI coarse seed found no active f blocks")

    layout = RHS1QICoarseBlockLayout(
        block_sizes=tuple(block_sizes),
        n_theta=n_theta,
        n_zeta=n_zeta,
        block_x=tuple(block_x),
        block_species=tuple(block_species),
    )
    basis_kind_norm = str(basis_kind).strip().lower().replace("-", "_")
    if basis_kind_norm in {"enriched", "hard_seed", "xblock_hard_seed", "schur"}:
        basis = build_rhs1_qi_xblock_hard_seed_basis(
            layout,
            max_candidates=max(1, int(max_candidates)),
            max_rank=max(1, int(max_rank)),
            max_angular_mode=max(0, int(max_angular_mode)),
            rtol=float(rank_rtol),
            include_radial=bool(include_radial),
            include_angular=bool(include_angular),
            include_radial_angular=bool(include_radial_angular),
            include_constraint_moments=bool(include_constraint_moments),
            include_schur=bool(include_schur),
            include_blocks=bool(include_blocks),
        )
    elif basis_kind_norm in {"legacy", "basic", "coarse"}:
        basis = build_rhs1_qi_coarse_basis(
            layout,
            max_rank=max(1, int(max_rank)),
            rtol=float(rank_rtol),
            include_angular=bool(include_angular),
            include_blocks=bool(include_blocks),
        )
    else:
        raise ValueError(f"Unknown QI coarse seed basis kind: {basis_kind!r}")
    basis_vectors = jnp.asarray(basis.vectors, dtype=jnp.float64)
    tail_size = int(linear_size) - int(basis_vectors.shape[0])
    if tail_size < 0:
        raise RuntimeError(
            "QI coarse seed basis is larger than the active x-block space "
            f"({basis_vectors.shape[0]} > {int(linear_size)})"
        )
    if tail_size > 0:
        basis_vectors = jnp.concatenate(
            [basis_vectors, jnp.zeros((tail_size, int(basis_vectors.shape[1])), dtype=jnp.float64)],
            axis=0,
        )
    return RHS1QICoarseBasis(vectors=basis_vectors, metadata=basis.metadata)


def _rhs1_xblock_qi_block_geometry_metadata(
    *,
    op: V3FullSystemOperator,
    active_dof: bool,
    linear_size: int,
    include_tail_block: bool = False,
) -> dict[str, object]:
    """Return x/species block metadata for matrix-free QI device helpers."""

    n_species = int(op.n_species)
    n_x = int(op.n_x)
    n_l = int(op.n_xi)
    n_theta = int(op.n_theta)
    n_zeta = int(op.n_zeta)
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    block_sizes: list[int] = []
    block_x: list[int] = []
    block_species: list[int] = []
    for s in range(n_species):
        for ix in range(n_x):
            n_lx = int(nxi_for_x[ix]) if bool(active_dof) else n_l
            size = int(max(0, n_lx) * n_theta * n_zeta)
            if size <= 0:
                continue
            block_sizes.append(size)
            block_x.append(ix)
            block_species.append(s)
    f_block_size = int(sum(block_sizes))
    tail_size = max(0, int(linear_size) - int(f_block_size))
    if bool(include_tail_block) and tail_size > 0:
        block_sizes.append(int(tail_size))
        block_x.append(-1)
        block_species.append(-1)
    return {
        "qi_block_sizes": tuple(int(value) for value in block_sizes),
        "qi_block_x": tuple(int(value) for value in block_x),
        "qi_block_species": tuple(int(value) for value in block_species),
        "qi_block_f_size": int(f_block_size),
        "qi_block_tail_size": int(tail_size),
        "qi_block_tail_included": bool(include_tail_block and tail_size > 0),
    }


def _rhs1_xblock_global_coarse_basis(
    *,
    op: V3FullSystemOperator,
    rhs: jnp.ndarray,
    preconditioner: Callable[[jnp.ndarray], jnp.ndarray],
    include_rhs: bool,
    fsavg_lmax: int,
    max_extra_units: int,
    max_directions: int,
) -> tuple[tuple[str, jnp.ndarray], ...]:
    """Build a fixed low-dimensional RHSMode=1 coarse basis.

    Unlike the post-Krylov residual basis above, this basis is fixed for the
    solve, so it can be used inside a linear two-level preconditioner. The
    directions target the global pieces an x-block preconditioner cannot remove:
    RHS-like components, flux-surface-averaged low-L moments across x, and
    constraint/source rows.
    """
    rhs = jnp.asarray(rhs, dtype=jnp.float64).reshape((-1,))
    total = int(op.total_size)
    directions: list[tuple[str, jnp.ndarray]] = []

    def _add(name: str, direction: jnp.ndarray) -> None:
        if len(directions) >= int(max_directions):
            return
        vec = jnp.asarray(direction, dtype=jnp.float64).reshape((-1,))
        if vec.shape != (total,):
            return
        try:
            norm = float(jnp.linalg.norm(vec))
        except Exception:
            return
        if np.isfinite(norm) and norm > 0.0:
            directions.append((str(name), vec))

    if include_rhs:
        try:
            _add("preconditioned_rhs", preconditioner(rhs))
        except Exception:
            pass
        _add("raw_rhs", rhs)

    extra_start = int(op.f_size + op.phi1_size)
    extra_size = int(op.extra_size)
    if extra_size > 0:
        rhs_extra = rhs[extra_start : extra_start + extra_size]
        extra_dir = jnp.zeros((total,), dtype=jnp.float64).at[extra_start : extra_start + extra_size].set(rhs_extra)
        _add("extra_rhs", extra_dir)
        if extra_size <= int(max_extra_units):
            for ie in range(extra_size):
                if len(directions) >= int(max_directions):
                    break
                unit = jnp.zeros((total,), dtype=jnp.float64).at[extra_start + ie].set(1.0)
                _add(f"extra_unit_{ie}", unit)

    if int(op.constraint_scheme) == 1:
        ix0 = _ix_min(bool(op.point_at_x0))
        source_basis = _source_basis_constraint_scheme_1(op.x)
        for s in range(int(op.n_species)):
            for ibasis, basis in enumerate(source_basis):
                if len(directions) >= int(max_directions):
                    break
                f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
                f_dir = f_dir.at[s, ix0:, 0, :, :].set(basis[ix0:, None, None])
                tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
                _add(f"constraint1_source_s{s}_{ibasis}", jnp.concatenate([f_dir.reshape((-1,)), tail]))

    lmax_use = min(max(0, int(fsavg_lmax)), max(0, int(op.n_xi) - 1))
    angular_norm = float(max(1, int(op.n_theta) * int(op.n_zeta))) ** -0.5
    for il in range(lmax_use + 1):
        for s in range(int(op.n_species)):
            for ix in range(int(op.n_x)):
                if len(directions) >= int(max_directions):
                    return tuple(directions)
                f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
                f_dir = f_dir.at[s, ix, il, :, :].set(angular_norm)
                tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
                _add(f"fsavg_s{s}_x{ix}_l{il}", jnp.concatenate([f_dir.reshape((-1,)), tail]))

    return tuple(directions)


def _rhs1_xblock_global_coupling_load_basis(
    *,
    op: V3FullSystemOperator,
    rhs: jnp.ndarray,
    include_rhs: bool,
    fsavg_lmax: int,
    angular_lmax: int,
    max_extra_units: int,
    max_directions: int,
) -> tuple[tuple[str, jnp.ndarray], ...]:
    """Build load vectors for a smoothed global-coupling x-block correction.

    The vectors represent the low-dimensional error channels that a per-x block
    inverse cannot see: conserved-source rows, low-L flux-surface averages, and
    the lowest theta/zeta Fourier components. The actual correction subspace is
    obtained by applying the base x-block preconditioner to these loads.
    """
    rhs = jnp.asarray(rhs, dtype=jnp.float64).reshape((-1,))
    total = int(op.total_size)
    directions: list[tuple[str, jnp.ndarray]] = []

    def _add(name: str, direction: jnp.ndarray) -> None:
        if len(directions) >= int(max_directions):
            return
        vec = jnp.asarray(direction, dtype=jnp.float64).reshape((-1,))
        if vec.shape != (total,):
            return
        try:
            norm = float(jnp.linalg.norm(vec))
        except Exception:
            return
        if np.isfinite(norm) and norm > 0.0:
            directions.append((str(name), vec))

    if include_rhs:
        _add("raw_rhs", rhs)

    extra_start = int(op.f_size + op.phi1_size)
    extra_size = int(op.extra_size)
    if extra_size > 0:
        rhs_extra = rhs[extra_start : extra_start + extra_size]
        extra_dir = jnp.zeros((total,), dtype=jnp.float64).at[extra_start : extra_start + extra_size].set(rhs_extra)
        _add("extra_rhs", extra_dir)
        if extra_size <= int(max_extra_units):
            for ie in range(extra_size):
                if len(directions) >= int(max_directions):
                    break
                unit = jnp.zeros((total,), dtype=jnp.float64).at[extra_start + ie].set(1.0)
                _add(f"extra_unit_{ie}", unit)

    if int(op.constraint_scheme) == 1:
        ix0 = _ix_min(bool(op.point_at_x0))
        source_basis = _source_basis_constraint_scheme_1(op.x)
        for s in range(int(op.n_species)):
            for ibasis, basis in enumerate(source_basis):
                if len(directions) >= int(max_directions):
                    break
                f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
                f_dir = f_dir.at[s, ix0:, 0, :, :].set(basis[ix0:, None, None])
                tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
                _add(f"constraint1_source_s{s}_{ibasis}", jnp.concatenate([f_dir.reshape((-1,)), tail]))

    lmax_use = min(max(0, int(fsavg_lmax)), max(0, int(op.n_xi) - 1))
    angular_norm = float(max(1, int(op.n_theta) * int(op.n_zeta))) ** -0.5
    for il in range(lmax_use + 1):
        for s in range(int(op.n_species)):
            for ix in range(int(op.n_x)):
                if len(directions) >= int(max_directions):
                    return tuple(directions)
                f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
                f_dir = f_dir.at[s, ix, il, :, :].set(angular_norm)
                tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
                _add(f"fsavg_s{s}_x{ix}_l{il}", jnp.concatenate([f_dir.reshape((-1,)), tail]))

    angular_l_use = min(max(0, int(angular_lmax)), max(0, int(op.n_xi) - 1))
    if angular_l_use >= 0 and int(op.n_theta) > 1 and int(op.n_zeta) > 1:
        theta = jnp.arange(int(op.n_theta), dtype=jnp.float64)
        zeta = jnp.arange(int(op.n_zeta), dtype=jnp.float64)
        two_pi = float(2.0 * np.pi)
        mode_pairs = ((1, 0), (0, 1), (1, 1), (1, -1), (2, 0), (0, 2), (2, 1), (1, 2))
        for il in range(angular_l_use + 1):
            for m_mode, n_mode in mode_pairs:
                phase = two_pi * (
                    float(m_mode) * theta[:, None] / float(max(1, int(op.n_theta)))
                    + float(n_mode) * zeta[None, :] / float(max(1, int(op.n_zeta)))
                )
                for parity, pattern in (("cos", jnp.cos(phase)), ("sin", jnp.sin(phase))):
                    pattern_norm = float(jnp.linalg.norm(pattern))
                    if (not np.isfinite(pattern_norm)) or pattern_norm <= 0.0:
                        continue
                    pattern = pattern / pattern_norm
                    for s in range(int(op.n_species)):
                        if len(directions) >= int(max_directions):
                            return tuple(directions)
                        f_dir = jnp.zeros(op.fblock.f_shape, dtype=jnp.float64)
                        f_dir = f_dir.at[s, :, il, :, :].set(pattern[None, :, :])
                        tail = jnp.zeros((total - op.f_size,), dtype=jnp.float64)
                        _add(
                            f"angular_s{s}_allx_l{il}_m{m_mode}_n{n_mode}_{parity}",
                            jnp.concatenate([f_dir.reshape((-1,)), tail]),
                        )

    return tuple(directions)


def _rhs1_xblock_smoothed_load_qi_basis(
    *,
    op: V3FullSystemOperator,
    rhs: jnp.ndarray,
    base_preconditioner: Callable[[jnp.ndarray], jnp.ndarray],
    direction_projector: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expected_size: int | None = None,
    include_rhs: bool,
    fsavg_lmax: int,
    angular_lmax: int,
    max_extra_units: int,
    max_directions: int,
    rank_rtol: float,
    max_rank: int,
) -> tuple[RHS1QICoarseBasis, dict[str, object]]:
    """Build a QI coarse basis from smoothed physics load vectors.

    This is the low-rank field-split/Schur candidate for the hard QI lane:
    load vectors represent source, flux-surface averaged, and low angular
    coupling channels, while the local x-block smoother maps those loads into
    prolongation directions. The resulting basis is still rank-gated and
    fail-closed by the caller before it can replace the baseline preconditioner.
    """

    expected_size_use = int(op.total_size) if expected_size is None else int(expected_size)
    max_dirs_use = max(1, int(max_directions))
    raw_loads = _rhs1_xblock_global_coupling_load_basis(
        op=op,
        rhs=rhs,
        include_rhs=bool(include_rhs),
        fsavg_lmax=int(fsavg_lmax),
        angular_lmax=int(angular_lmax),
        max_extra_units=int(max_extra_units),
        max_directions=max_dirs_use,
    )
    columns: list[jnp.ndarray] = []
    labels: list[str] = []
    for name, load in raw_loads[:max_dirs_use]:
        load_vec = jnp.asarray(load, dtype=jnp.float64).reshape((-1,))
        if direction_projector is not None:
            load_vec = jnp.asarray(direction_projector(load_vec), dtype=jnp.float64).reshape((-1,))
        if int(load_vec.shape[0]) != expected_size_use:
            continue
        try:
            load_norm = float(jnp.linalg.norm(load_vec))
        except Exception:
            continue
        if not np.isfinite(load_norm) or load_norm <= 0.0:
            continue
        try:
            smoothed = jnp.asarray(
                base_preconditioner(load_vec / jnp.asarray(load_norm, dtype=load_vec.dtype)),
                dtype=jnp.float64,
            ).reshape((-1,))
        except Exception:
            continue
        if int(smoothed.shape[0]) != expected_size_use:
            continue
        try:
            smooth_norm = float(jnp.linalg.norm(smoothed))
        except Exception:
            continue
        if not np.isfinite(smooth_norm) or smooth_norm <= 0.0:
            continue
        columns.append(smoothed / jnp.asarray(smooth_norm, dtype=smoothed.dtype))
        labels.append(f"smoothed_load:{name}")

    if not columns:
        raise RuntimeError("smoothed-load QI basis found no valid preconditioned load directions")

    candidates = jnp.stack(tuple(columns), axis=1)
    basis = orthonormalize_rhs1_qi_coarse_basis(
        candidates,
        labels=tuple(labels),
        rtol=float(rank_rtol),
        max_rank=max(1, int(max_rank)),
    )
    metadata = {
        "load_basis_size": int(len(raw_loads)),
        "smoothed_candidate_count": int(len(columns)),
        "rank": int(basis.metadata.rank),
        "max_directions": int(max_dirs_use),
        "max_rank": int(max_rank),
        "fsavg_lmax": int(fsavg_lmax),
        "angular_lmax": int(angular_lmax),
        "include_rhs": bool(include_rhs),
        "accepted_labels": tuple(basis.metadata.accepted_labels),
    }
    return basis, metadata


def _build_rhs1_xblock_two_level_preconditioner(
    *,
    op: V3FullSystemOperator,
    rhs: jnp.ndarray,
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    base_preconditioner: Callable[[jnp.ndarray], jnp.ndarray],
    direction_projector: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expected_size: int | None = None,
    mode: str,
    fsavg_lmax: int,
    max_extra_units: int,
    max_directions: int,
    rcond: float,
    include_rhs: bool,
    emit: Callable[[int, str], None] | None = None,
) -> tuple[Callable[[jnp.ndarray], jnp.ndarray], dict[str, object], dict[str, int]]:
    """Wrap the x-block preconditioner with a fixed two-level coarse inverse."""
    from scipy.linalg import qr, solve_triangular  # noqa: PLC0415

    mode_use = str(mode).strip().lower().replace("-", "_")
    if mode_use not in {"additive", "multiplicative"}:
        mode_use = "additive"
    max_dirs_use = max(1, int(max_directions))
    expected_size_use = int(op.total_size) if expected_size is None else int(expected_size)
    raw_directions = _rhs1_xblock_global_coarse_basis(
        op=op,
        rhs=rhs,
        preconditioner=base_preconditioner,
        include_rhs=bool(include_rhs),
        fsavg_lmax=int(fsavg_lmax),
        max_extra_units=int(max_extra_units),
        max_directions=max_dirs_use,
    )
    basis_cols: list[np.ndarray] = []
    abasis_cols: list[np.ndarray] = []
    names: list[str] = []
    for name, direction in raw_directions[:max_dirs_use]:
        if direction_projector is not None:
            direction = direction_projector(direction)
        direction_np = np.asarray(jax.device_get(direction), dtype=np.float64).reshape((-1,))
        if direction_np.shape != (expected_size_use,) or not np.all(np.isfinite(direction_np)):
            continue
        norm = float(np.linalg.norm(direction_np))
        if (not np.isfinite(norm)) or norm <= 0.0:
            continue
        direction_np = direction_np / norm
        a_direction = np.asarray(
            jax.device_get(matvec(jnp.asarray(direction_np, dtype=jnp.float64))),
            dtype=np.float64,
        ).reshape((-1,))
        if a_direction.shape != direction_np.shape or not np.all(np.isfinite(a_direction)):
            continue
        a_norm = float(np.linalg.norm(a_direction))
        if (not np.isfinite(a_norm)) or a_norm <= 0.0:
            continue
        names.append(str(name))
        basis_cols.append(direction_np)
        abasis_cols.append(a_direction)

    if not basis_cols:
        raise RuntimeError("two-level x-block preconditioner found no valid coarse directions")

    basis = np.column_stack(basis_cols)
    abasis = np.column_stack(abasis_cols)
    q, r, piv = qr(abasis, mode="economic", pivoting=True)
    diag = np.abs(np.diag(r))
    if diag.size == 0:
        raise RuntimeError("two-level x-block preconditioner coarse QR is empty")
    threshold = max(float(rcond), 0.0) * max(float(diag[0]), 1.0)
    rank = int(np.count_nonzero(diag > threshold))
    if rank <= 0:
        raise RuntimeError("two-level x-block preconditioner coarse QR is rank deficient")
    piv_use = np.asarray(piv[:rank], dtype=np.int32)
    q_use = np.asarray(q[:, :rank], dtype=np.float64)
    r_use = np.asarray(r[:rank, :rank], dtype=np.float64)
    basis_use = np.asarray(basis[:, piv_use], dtype=np.float64)
    names_use = tuple(names[int(i)] for i in piv_use)
    stats = {"applies": 0, "coarse_applies": 0}

    def _coarse_correction(vec_np: np.ndarray) -> np.ndarray:
        rhs_small = q_use.T @ np.asarray(vec_np, dtype=np.float64).reshape((-1,))
        coeff = solve_triangular(r_use, rhs_small, lower=False, check_finite=False)
        return basis_use @ np.asarray(coeff, dtype=np.float64).reshape((-1,))

    def _apply(v: jnp.ndarray) -> jnp.ndarray:
        stats["applies"] += 1
        v_np = np.asarray(jax.device_get(v), dtype=np.float64).reshape((-1,))
        base = np.asarray(
            jax.device_get(base_preconditioner(jnp.asarray(v_np, dtype=jnp.float64))),
            dtype=np.float64,
        ).reshape((-1,))
        if mode_use == "multiplicative":
            abase = np.asarray(
                jax.device_get(matvec(jnp.asarray(base, dtype=jnp.float64))),
                dtype=np.float64,
            ).reshape((-1,))
            coarse_input = v_np - abase
        else:
            coarse_input = v_np
        correction = _coarse_correction(coarse_input)
        stats["coarse_applies"] += 1
        return jnp.asarray(base + correction, dtype=jnp.float64)

    metadata: dict[str, object] = {
        "mode": mode_use,
        "basis_size": int(len(basis_cols)),
        "rank": int(rank),
        "requested_max_directions": int(max_dirs_use),
        "fsavg_lmax": int(fsavg_lmax),
        "include_rhs": bool(include_rhs),
        "rcond": float(rcond),
        "basis_names": names_use,
        "active_projected": bool(direction_projector is not None),
        "expected_size": int(expected_size_use),
    }
    if emit is not None:
        emit(
            0,
            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres two-level coarse "
            f"built mode={mode_use} basis={len(basis_cols)} rank={rank}",
        )
    return _apply, metadata, stats


def _build_rhs1_xblock_smoothed_global_coupling_preconditioner(
    *,
    op: V3FullSystemOperator,
    rhs: jnp.ndarray,
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    base_preconditioner: Callable[[jnp.ndarray], jnp.ndarray],
    direction_projector: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expected_size: int | None = None,
    mode: str,
    fsavg_lmax: int,
    angular_lmax: int,
    max_extra_units: int,
    max_directions: int,
    rcond: float,
    include_rhs: bool,
    max_setup_s: float = 0.0,
    emit: Callable[[int, str], None] | None = None,
) -> tuple[Callable[[jnp.ndarray], jnp.ndarray], dict[str, object], dict[str, int]]:
    """Wrap x-block LU with a smoothed low-rank global-coupling correction.

    This is a constrained two-level method. The load basis ``P`` is deliberately
    low rank and physics-aware, the correction basis is ``Z = B^{-1} P`` using
    the already-built per-x preconditioner, and the coarse solve minimizes
    ``||r - A Z c||``. It keeps setup bounded while giving GMRES a fixed global
    subspace for flux-surface, source, and low Fourier coupling modes.
    """
    from scipy.linalg import qr, solve_triangular  # noqa: PLC0415

    mode_use = str(mode).strip().lower().replace("-", "_")
    if mode_use not in {"additive", "multiplicative"}:
        mode_use = "additive"
    smoother = (
        os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_PC_GLOBAL_COUPLING_SMOOTHER", "base")
        .strip()
        .lower()
        .replace("-", "_")
    )
    if smoother in {"none", "raw", "identity", "load", "loads"}:
        smoother = "identity"
    elif smoother in {"preconditioner", "preconditioned"}:
        smoother = "base"
    elif smoother != "base":
        smoother = "base"
    max_dirs_use = max(1, int(max_directions))
    max_setup_s_use = max(0.0, float(max_setup_s))
    setup_deadline = time.perf_counter() + max_setup_s_use if max_setup_s_use > 0.0 else None
    setup_budget_reached = False
    expected_size_use = int(op.total_size) if expected_size is None else int(expected_size)
    raw_loads = _rhs1_xblock_global_coupling_load_basis(
        op=op,
        rhs=rhs,
        include_rhs=bool(include_rhs),
        fsavg_lmax=int(fsavg_lmax),
        angular_lmax=int(angular_lmax),
        max_extra_units=int(max_extra_units),
        max_directions=max_dirs_use,
    )
    z_cols: list[np.ndarray] = []
    az_cols: list[np.ndarray] = []
    names: list[str] = []
    for name, load in raw_loads[:max_dirs_use]:
        if direction_projector is not None:
            load = direction_projector(load)
        load_np = np.asarray(jax.device_get(load), dtype=np.float64).reshape((-1,))
        if load_np.shape != (expected_size_use,) or not np.all(np.isfinite(load_np)):
            continue
        load_norm = float(np.linalg.norm(load_np))
        if (not np.isfinite(load_norm)) or load_norm <= 0.0:
            continue
        if smoother == "identity":
            smoothed = np.asarray(load_np / load_norm, dtype=np.float64)
        else:
            smoothed = np.asarray(
                jax.device_get(base_preconditioner(jnp.asarray(load_np / load_norm, dtype=jnp.float64))),
                dtype=np.float64,
            ).reshape((-1,))
        if smoothed.shape != load_np.shape or not np.all(np.isfinite(smoothed)):
            continue
        z_norm = float(np.linalg.norm(smoothed))
        if (not np.isfinite(z_norm)) or z_norm <= 0.0:
            continue
        smoothed = smoothed / z_norm
        a_smoothed = np.asarray(
            jax.device_get(matvec(jnp.asarray(smoothed, dtype=jnp.float64))),
            dtype=np.float64,
        ).reshape((-1,))
        if a_smoothed.shape != smoothed.shape or not np.all(np.isfinite(a_smoothed)):
            continue
        a_norm = float(np.linalg.norm(a_smoothed))
        if (not np.isfinite(a_norm)) or a_norm <= 0.0:
            continue
        names.append(str(name))
        z_cols.append(smoothed)
        az_cols.append(a_smoothed)
        if setup_deadline is not None and time.perf_counter() >= setup_deadline:
            setup_budget_reached = True
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres global-coupling "
                    f"setup budget reached after basis={len(z_cols)}/{len(raw_loads)} "
                    f"max_setup_s={max_setup_s_use:.3f}; using partial basis",
                )
            break

    if not z_cols:
        raise RuntimeError("global-coupling x-block preconditioner found no valid smoothed directions")

    z_basis = np.column_stack(z_cols)
    az_basis = np.column_stack(az_cols)
    q, r, piv = qr(az_basis, mode="economic", pivoting=True)
    diag = np.abs(np.diag(r))
    if diag.size == 0:
        raise RuntimeError("global-coupling x-block preconditioner coarse QR is empty")
    threshold = max(float(rcond), 0.0) * max(float(diag[0]), 1.0)
    rank = int(np.count_nonzero(diag > threshold))
    if rank <= 0:
        raise RuntimeError("global-coupling x-block preconditioner coarse QR is rank deficient")
    piv_use = np.asarray(piv[:rank], dtype=np.int32)
    q_use = np.asarray(q[:, :rank], dtype=np.float64)
    r_use = np.asarray(r[:rank, :rank], dtype=np.float64)
    z_use = np.asarray(z_basis[:, piv_use], dtype=np.float64)
    names_use = tuple(names[int(i)] for i in piv_use)
    stats = {"applies": 0, "coarse_applies": 0}

    def _coarse_correction(vec_np: np.ndarray) -> np.ndarray:
        rhs_small = q_use.T @ np.asarray(vec_np, dtype=np.float64).reshape((-1,))
        coeff = solve_triangular(r_use, rhs_small, lower=False, check_finite=False)
        return z_use @ np.asarray(coeff, dtype=np.float64).reshape((-1,))

    def _apply(v: jnp.ndarray) -> jnp.ndarray:
        stats["applies"] += 1
        v_np = np.asarray(jax.device_get(v), dtype=np.float64).reshape((-1,))
        base = np.asarray(
            jax.device_get(base_preconditioner(jnp.asarray(v_np, dtype=jnp.float64))),
            dtype=np.float64,
        ).reshape((-1,))
        if mode_use == "multiplicative":
            abase = np.asarray(
                jax.device_get(matvec(jnp.asarray(base, dtype=jnp.float64))),
                dtype=np.float64,
            ).reshape((-1,))
            coarse_input = v_np - abase
        else:
            coarse_input = v_np
        correction = _coarse_correction(coarse_input)
        stats["coarse_applies"] += 1
        return jnp.asarray(base + correction, dtype=jnp.float64)

    metadata: dict[str, object] = {
        "mode": mode_use,
        "load_basis_size": int(len(raw_loads)),
        "basis_size": int(len(z_cols)),
        "rank": int(rank),
        "requested_max_directions": int(max_dirs_use),
        "fsavg_lmax": int(fsavg_lmax),
        "angular_lmax": int(angular_lmax),
        "include_rhs": bool(include_rhs),
        "rcond": float(rcond),
        "smoother": smoother,
        "setup_budget_s": float(max_setup_s_use),
        "setup_budget_reached": bool(setup_budget_reached),
        "basis_names": names_use,
    }
    if emit is not None:
        emit(
            0,
            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres global-coupling "
            f"built mode={mode_use} smoother={smoother} loads={len(raw_loads)} basis={len(z_cols)} rank={rank}",
        )
    return _apply, metadata, stats


def _build_rhs1_xblock_device_global_coupling_preconditioner(
    *,
    op: V3FullSystemOperator,
    rhs: jnp.ndarray,
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    base_preconditioner: Callable[[jnp.ndarray], jnp.ndarray],
    direction_projector: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expected_size: int | None = None,
    mode: str,
    fsavg_lmax: int,
    angular_lmax: int,
    max_extra_units: int,
    max_directions: int,
    rcond: float,
    include_rhs: bool,
    max_setup_s: float = 0.0,
    emit: Callable[[int, str], None] | None = None,
) -> tuple[Callable[[jnp.ndarray], jnp.ndarray], dict[str, object], dict[str, int]]:
    """Build a JAX-array global-coupling correction for device Krylov paths.

    The host global-coupling helper above is useful for SciPy Krylov probes but
    applies a coarse correction through host QR factors on every Krylov step.
    This variant performs the same physics-aware load smoothing, then stores
    ``Z`` and the rank-revealed coarse least-squares factors as JAX arrays so
    Krylov iterations remain device-resident. The default QR path avoids the
    squared conditioning of the older normal-equation correction.
    """
    from scipy.linalg import qr  # noqa: PLC0415

    mode_use = str(mode).strip().lower().replace("-", "_")
    if mode_use not in {"additive", "multiplicative"}:
        mode_use = "additive"
    coarse_solver = (
        os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_PC_GLOBAL_COUPLING_DEVICE_SOLVER", "qr")
        .strip()
        .lower()
        .replace("-", "_")
    )
    if coarse_solver in {"normal", "normal_equation", "normal_equations", "ridge"}:
        coarse_solver = "normal_equations"
    elif coarse_solver not in {"qr", "pivoted_qr"}:
        coarse_solver = "qr"
    smoother = (
        os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_PC_GLOBAL_COUPLING_SMOOTHER", "identity")
        .strip()
        .lower()
        .replace("-", "_")
    )
    if smoother in {"none", "raw", "identity", "load", "loads"}:
        smoother = "identity"
    elif smoother in {"base", "preconditioner", "preconditioned"}:
        smoother = "base"
    else:
        smoother = "identity"
    expected_size_use = int(op.total_size) if expected_size is None else int(expected_size)
    max_dirs_use = max(1, int(max_directions))
    max_setup_s_use = max(0.0, float(max_setup_s))
    setup_deadline = time.perf_counter() + max_setup_s_use if max_setup_s_use > 0.0 else None
    setup_budget_reached = False
    raw_loads = _rhs1_xblock_global_coupling_load_basis(
        op=op,
        rhs=rhs,
        include_rhs=bool(include_rhs),
        fsavg_lmax=int(fsavg_lmax),
        angular_lmax=int(angular_lmax),
        max_extra_units=int(max_extra_units),
        max_directions=max_dirs_use,
    )
    z_cols: list[jnp.ndarray] = []
    az_cols: list[jnp.ndarray] = []
    names: list[str] = []
    for name, load in raw_loads[:max_dirs_use]:
        if direction_projector is not None:
            load = direction_projector(load)
        load_j = jnp.asarray(load, dtype=jnp.float64).reshape((-1,))
        if load_j.shape != (expected_size_use,):
            continue
        load_np = np.asarray(jax.device_get(load_j), dtype=np.float64)
        if not np.all(np.isfinite(load_np)):
            continue
        load_norm = float(np.linalg.norm(load_np))
        if (not np.isfinite(load_norm)) or load_norm <= 0.0:
            continue
        load_unit = jnp.asarray(load_np / load_norm, dtype=jnp.float64)
        if smoother == "identity":
            z = load_unit
        else:
            z = jnp.asarray(base_preconditioner(load_unit), dtype=jnp.float64).reshape((-1,))
        z_np = np.asarray(jax.device_get(z), dtype=np.float64)
        if z_np.shape != load_np.shape or not np.all(np.isfinite(z_np)):
            continue
        z_norm = float(np.linalg.norm(z_np))
        if (not np.isfinite(z_norm)) or z_norm <= 0.0:
            continue
        z = jnp.asarray(z_np / z_norm, dtype=jnp.float64)
        az = jnp.asarray(matvec(z), dtype=jnp.float64).reshape((-1,))
        az_np = np.asarray(jax.device_get(az), dtype=np.float64)
        if az_np.shape != z_np.shape or not np.all(np.isfinite(az_np)):
            continue
        az_norm = float(np.linalg.norm(az_np))
        if (not np.isfinite(az_norm)) or az_norm <= 0.0:
            continue
        names.append(str(name))
        z_cols.append(z)
        az_cols.append(az)
        if setup_deadline is not None and time.perf_counter() >= setup_deadline:
            setup_budget_reached = True
            if emit is not None:
                emit(
                    1,
                    "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres device global-coupling "
                    f"setup budget reached after basis={len(z_cols)}/{len(raw_loads)} "
                    f"max_setup_s={max_setup_s_use:.3f}; using partial basis",
                )
            break

    if not z_cols:
        raise RuntimeError("device global-coupling x-block preconditioner found no valid smoothed directions")

    z_basis_np = np.column_stack([np.asarray(jax.device_get(col), dtype=np.float64) for col in z_cols])
    az_basis_np = np.column_stack([np.asarray(jax.device_get(col), dtype=np.float64) for col in az_cols])
    if not np.all(np.isfinite(z_basis_np)) or not np.all(np.isfinite(az_basis_np)):
        raise RuntimeError("device global-coupling x-block preconditioner found non-finite coarse columns")

    ridge_value = 0.0
    names_use = tuple(names)
    singular_values: np.ndarray
    r_diag: np.ndarray
    if coarse_solver == "normal_equations":
        z_basis = jnp.asarray(z_basis_np, dtype=jnp.float64)
        az_basis = jnp.asarray(az_basis_np, dtype=jnp.float64)
        gram = az_basis.T @ az_basis
        diag_scale = jnp.maximum(jnp.max(jnp.abs(jnp.diag(gram))), jnp.asarray(1.0, dtype=jnp.float64))
        ridge = jnp.asarray(max(float(rcond), 1.0e-14), dtype=jnp.float64) * diag_scale
        coarse_inv = jnp.linalg.inv(gram + ridge * jnp.eye(int(gram.shape[0]), dtype=jnp.float64))
        gram_eigs = jnp.maximum(jnp.linalg.eigvalsh(gram), jnp.asarray(0.0, dtype=jnp.float64))
        singular_values = np.asarray(jax.device_get(jnp.sqrt(gram_eigs[::-1])), dtype=np.float64)
        if singular_values.size == 0 or not np.all(np.isfinite(singular_values)):
            raise RuntimeError("device global-coupling x-block preconditioner coarse spectrum is invalid")
        rank_threshold = max(float(rcond), 0.0) * max(float(np.max(singular_values, initial=0.0)), 1.0)
        rank = int(np.count_nonzero(singular_values > rank_threshold))
        if rank <= 0:
            raise RuntimeError("device global-coupling x-block preconditioner coarse system is rank deficient")
        ridge_value = float(jax.device_get(ridge))
        r_diag = singular_values

        def _coarse_coeff(coarse_input: jnp.ndarray) -> jnp.ndarray:
            return coarse_inv @ (az_basis.T @ coarse_input)

    else:
        q, r, piv = qr(az_basis_np, mode="economic", pivoting=True)
        diag = np.abs(np.diag(r))
        if diag.size == 0 or not np.all(np.isfinite(diag)):
            raise RuntimeError("device global-coupling x-block preconditioner coarse QR is empty")
        rank_threshold = max(float(rcond), 0.0) * max(float(diag[0]), 1.0)
        rank = int(np.count_nonzero(diag > rank_threshold))
        if rank <= 0:
            raise RuntimeError("device global-coupling x-block preconditioner coarse QR is rank deficient")
        piv_use = np.asarray(piv[:rank], dtype=np.int32)
        q_use = jnp.asarray(q[:, :rank], dtype=jnp.float64)
        r_use = jnp.asarray(r[:rank, :rank], dtype=jnp.float64)
        z_basis = jnp.asarray(z_basis_np[:, piv_use], dtype=jnp.float64)
        # The diagonal of pivoted R is a cheap, rank-revealed singular-value proxy.
        r_diag = np.asarray(diag[:rank], dtype=np.float64)
        singular_values = r_diag
        names_use = tuple(names[int(i)] for i in piv_use)

        def _coarse_coeff(coarse_input: jnp.ndarray) -> jnp.ndarray:
            return jnp.linalg.solve(r_use, q_use.T @ coarse_input)

    stats = {"applies": 0, "coarse_applies": 0}

    def _apply(v: jnp.ndarray) -> jnp.ndarray:
        stats["applies"] += 1
        v_j = jnp.asarray(v, dtype=jnp.float64)
        base = jnp.asarray(base_preconditioner(v_j), dtype=jnp.float64)
        if mode_use == "multiplicative":
            coarse_input = v_j - jnp.asarray(matvec(base), dtype=jnp.float64)
        else:
            coarse_input = v_j
        coeff = _coarse_coeff(coarse_input)
        stats["coarse_applies"] += 1
        return base + z_basis @ coeff

    metadata: dict[str, object] = {
        "mode": mode_use,
        "load_basis_size": int(len(raw_loads)),
        "basis_size": int(z_basis.shape[1]),
        "rank": int(rank),
        "requested_max_directions": int(max_dirs_use),
        "fsavg_lmax": int(fsavg_lmax),
        "angular_lmax": int(angular_lmax),
        "include_rhs": bool(include_rhs),
        "rcond": float(rcond),
        "coarse_solver": coarse_solver,
        "smoother": smoother,
        "ridge": float(ridge_value),
        "setup_budget_s": float(max_setup_s_use),
        "setup_budget_reached": bool(setup_budget_reached),
        "basis_names": names_use,
        "device_resident": True,
        "singular_values": tuple(float(v) for v in singular_values[: min(int(singular_values.size), 16)]),
        "r_diag": tuple(float(v) for v in r_diag[: min(int(r_diag.size), 16)]),
    }
    if emit is not None:
        emit(
            0,
            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres device global-coupling "
            f"built mode={mode_use} smoother={smoother} coarse_solver={coarse_solver} "
            f"loads={len(raw_loads)} basis={int(z_basis.shape[1])} rank={rank}",
        )
    return _apply, metadata, stats


def _build_rhs1_xblock_constraint1_moment_schur_preconditioner(
    *,
    op: V3FullSystemOperator,
    base_preconditioner: Callable[[jnp.ndarray], jnp.ndarray],
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    rcond: float = 1.0e-12,
    emit: Callable[[int, str], None] | None = None,
) -> tuple[Callable[[jnp.ndarray], jnp.ndarray], dict[str, object], dict[str, int]]:
    """Wrap an x-block preconditioner with a constraintScheme=1 moment Schur solve.

    The constraintScheme=1 system has source unknowns that enforce density and
    pressure moments. Per-x block preconditioners leave these global rows as a
    slow saddle-point mode. This wrapper builds the small dense approximation
    ``S = C M^{-1} B`` once, where ``B`` injects particle/energy sources and
    ``C`` returns density/pressure moments, then applies the block inverse using
    the supplied preconditioner as ``M^{-1}``.
    """
    from scipy.linalg import qr  # noqa: PLC0415

    if int(op.rhs_mode) != 1 or int(op.constraint_scheme) != 1:
        raise RuntimeError("constraint1 moment Schur requires RHSMode=1 constraintScheme=1")
    if int(op.phi1_size) != 0:
        raise RuntimeError("constraint1 moment Schur currently requires includePhi1=false")
    extra_size = int(op.extra_size)
    n_species = int(op.n_species)
    if extra_size != 2 * n_species or extra_size <= 0:
        raise RuntimeError("constraint1 moment Schur expected two source unknowns per species")

    reduced_probe = (
        jnp.zeros((op.total_size,), dtype=jnp.float64)
        if reduce_full is None
        else reduce_full(jnp.zeros((op.total_size,), dtype=jnp.float64))
    )
    expected_size = int(reduced_probe.size)
    f_size = int(op.f_size)
    zeros_extra = jnp.zeros((extra_size,), dtype=jnp.float64)
    rcond_use = max(0.0, float(rcond))

    def _to_full(v: jnp.ndarray) -> jnp.ndarray:
        v = jnp.asarray(v, dtype=jnp.float64).reshape((-1,))
        if expand_reduced is None:
            return v
        return jnp.asarray(expand_reduced(v), dtype=jnp.float64).reshape((-1,))

    def _from_full(v: jnp.ndarray) -> jnp.ndarray:
        v = jnp.asarray(v, dtype=jnp.float64).reshape((-1,))
        if reduce_full is None:
            return v
        return jnp.asarray(reduce_full(v), dtype=jnp.float64).reshape((-1,))

    def _base_full(v_full: jnp.ndarray) -> jnp.ndarray:
        v_full = jnp.asarray(v_full, dtype=jnp.float64).reshape((-1,))
        if reduce_full is None or expand_reduced is None:
            return jnp.asarray(base_preconditioner(v_full), dtype=jnp.float64).reshape((-1,))
        z_reduced = base_preconditioner(reduce_full(v_full))
        return jnp.asarray(expand_reduced(z_reduced), dtype=jnp.float64).reshape((-1,))

    s_mat = np.zeros((extra_size, extra_size), dtype=np.float64)
    for j in range(extra_size):
        src = np.zeros((n_species, 2), dtype=np.float64)
        src.reshape((-1,))[j] = 1.0
        f_src = _constraint_scheme1_inject_source(op, jnp.asarray(src, dtype=jnp.float64))
        y_full = _base_full(jnp.concatenate([f_src, zeros_extra], axis=0))
        y_f = y_full[:f_size].reshape(op.fblock.f_shape)
        s_col = _constraint_scheme1_moments_from_f(op, y_f).reshape((-1,))
        s_mat[:, j] = np.asarray(jax.device_get(s_col), dtype=np.float64)

    if not np.all(np.isfinite(s_mat)):
        raise RuntimeError("constraint1 moment Schur matrix contains non-finite values")
    _q, r, _piv = qr(s_mat, mode="economic", pivoting=True)
    diag = np.abs(np.diag(r))
    if diag.size == 0:
        raise RuntimeError("constraint1 moment Schur QR is empty")
    threshold = rcond_use * max(float(diag[0]), 1.0)
    rank = int(np.count_nonzero(diag > threshold))
    if rank <= 0:
        raise RuntimeError("constraint1 moment Schur is rank deficient")
    allow_rank_deficient_env = os.environ.get(
        "SFINCS_JAX_RHSMODE1_XBLOCK_PC_MOMENT_SCHUR_ALLOW_RANK_DEFICIENT",
        "",
    ).strip().lower()
    allow_rank_deficient = allow_rank_deficient_env in {"1", "true", "t", "yes", "on", ".true.", ".t."}
    if rank < extra_size and not allow_rank_deficient:
        raise RuntimeError(
            "constraint1 moment Schur is numerically rank deficient "
            f"(rank={rank} < extra={extra_size}); refusing unstable pseudo-inverse"
        )
    if rank == extra_size:
        try:
            schur_inv_np = np.linalg.inv(s_mat)
        except np.linalg.LinAlgError:
            schur_inv_np = np.linalg.pinv(s_mat, rcond=max(rcond_use, 1.0e-12))
    else:
        schur_inv_np = np.linalg.pinv(s_mat, rcond=max(rcond_use, 1.0e-12))
    if not np.all(np.isfinite(schur_inv_np)):
        raise RuntimeError("constraint1 moment Schur inverse contains non-finite values")
    schur_inv = jnp.asarray(schur_inv_np, dtype=jnp.float64)
    stats = {"applies": 0, "base_applies": 0}

    def _apply(v: jnp.ndarray) -> jnp.ndarray:
        stats["applies"] += 1
        r_full = _to_full(v)
        r_f = r_full[:f_size]
        r_e = r_full[f_size : f_size + extra_size]
        y_full = _base_full(jnp.concatenate([r_f, zeros_extra], axis=0))
        stats["base_applies"] += 1
        y_f = y_full[:f_size].reshape(op.fblock.f_shape)
        c_y = _constraint_scheme1_moments_from_f(op, y_f).reshape((-1,))
        x_e = schur_inv @ (c_y - r_e)
        f_corr = _constraint_scheme1_inject_source(op, x_e.reshape((n_species, 2)))
        y_corr = _base_full(jnp.concatenate([r_f - f_corr, zeros_extra], axis=0))
        stats["base_applies"] += 1
        out_full = jnp.concatenate([y_corr[:f_size], x_e], axis=0)
        return _from_full(out_full)

    metadata: dict[str, object] = {
        "mode": "constraint1_moment_schur",
        "extra_size": int(extra_size),
        "rank": int(rank),
        "rcond": float(rcond_use),
        "expected_size": int(expected_size),
        "singular_value_proxy": tuple(float(v) for v in diag[: min(int(diag.size), 16)]),
        "device_resident": True,
        "rank_deficient_allowed": bool(allow_rank_deficient),
    }
    if emit is not None:
        emit(
            0,
            "solve_v3_full_system_linear_gmres: xblock_sparse_pc_gmres "
            f"constraint1 moment-Schur built extra={extra_size} rank={rank}",
        )
    return _apply, metadata, stats


def _apply_subspace_minres_correction(
    *,
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    rhs: jnp.ndarray,
    x0: jnp.ndarray,
    direction_builder: Callable[[jnp.ndarray], Sequence[tuple[str, jnp.ndarray]]],
    steps: int,
    max_directions: int,
    alpha_clip: float = 0.0,
    rcond: float = 1.0e-12,
    min_improvement: float = 0.0,
) -> tuple[jnp.ndarray, jnp.ndarray, tuple[float, ...], tuple[int, ...], tuple[str, ...]]:
    """Apply accepted least-squares residual corrections over a small basis.

    This is a matrix-free coarse solve: it forms only ``A d_i`` for a bounded
    number of candidate directions, solves ``min_alpha ||r - A D alpha||_2``,
    and accepts the update only when the true residual decreases.
    """
    rhs = jnp.asarray(rhs, dtype=jnp.float64)
    x = jnp.asarray(x0, dtype=jnp.float64)
    residual = rhs - jnp.asarray(matvec(x), dtype=jnp.float64)
    residual_norm = float(jnp.linalg.norm(residual))
    history: list[float] = [residual_norm]
    accepted_counts: list[int] = []
    accepted_names: list[str] = []
    steps_use = max(0, int(steps))
    max_dirs_use = max(1, int(max_directions))
    alpha_clip_use = max(0.0, float(alpha_clip))
    rcond_use = max(0.0, float(rcond))
    min_improvement_use = max(0.0, float(min_improvement))

    for _ in range(steps_use):
        raw_directions = tuple(direction_builder(residual))[:max_dirs_use]
        names: list[str] = []
        basis_cols: list[np.ndarray] = []
        abasis_cols: list[np.ndarray] = []
        for name, direction in raw_directions:
            direction_np = np.asarray(jax.device_get(direction), dtype=np.float64).reshape((-1,))
            if direction_np.shape != (int(x.size),) or not np.all(np.isfinite(direction_np)):
                continue
            norm = float(np.linalg.norm(direction_np))
            if (not np.isfinite(norm)) or norm <= 0.0:
                continue
            direction_np = direction_np / norm
            a_direction = np.asarray(
                jax.device_get(matvec(jnp.asarray(direction_np, dtype=jnp.float64))),
                dtype=np.float64,
            ).reshape((-1,))
            if a_direction.shape != direction_np.shape or not np.all(np.isfinite(a_direction)):
                continue
            a_norm = float(np.linalg.norm(a_direction))
            if (not np.isfinite(a_norm)) or a_norm <= 0.0:
                continue
            names.append(str(name))
            basis_cols.append(direction_np)
            abasis_cols.append(a_direction)
        if not basis_cols:
            break

        residual_np = np.asarray(jax.device_get(residual), dtype=np.float64).reshape((-1,))
        basis = np.column_stack(basis_cols)
        abasis = np.column_stack(abasis_cols)
        try:
            coeff, *_ = np.linalg.lstsq(abasis, residual_np, rcond=rcond_use if rcond_use > 0.0 else None)
        except np.linalg.LinAlgError:
            coeff = np.linalg.pinv(abasis, rcond=max(rcond_use, 1.0e-12)) @ residual_np
        coeff = np.asarray(coeff, dtype=np.float64).reshape((-1,))
        if alpha_clip_use > 0.0:
            coeff = np.clip(coeff, -alpha_clip_use, alpha_clip_use)
        if not np.all(np.isfinite(coeff)):
            break
        trial_residual_np = residual_np - abasis @ coeff
        trial_norm = float(np.linalg.norm(trial_residual_np))
        if (not np.isfinite(trial_norm)) or trial_norm >= residual_norm * (1.0 - min_improvement_use):
            break
        x_np = np.asarray(jax.device_get(x), dtype=np.float64).reshape((-1,)) + basis @ coeff
        x = jnp.asarray(x_np, dtype=jnp.float64)
        residual = jnp.asarray(trial_residual_np, dtype=jnp.float64)
        residual_norm = trial_norm
        history.append(residual_norm)
        accepted_counts.append(int(len(basis_cols)))
        accepted_names.extend(names)

    return x, residual, tuple(history), tuple(accepted_counts), tuple(accepted_names)


def _apply_device_subspace_residual_equation_correction(
    *,
    matvec: Callable[[jnp.ndarray], jnp.ndarray],
    rhs: jnp.ndarray,
    x0: jnp.ndarray,
    direction_builder: Callable[[jnp.ndarray], Sequence[tuple[str, jnp.ndarray]]] | None,
    steps: int,
    max_directions: int,
    cached_basis: jnp.ndarray | None = None,
    cached_operator_on_basis: jnp.ndarray | None = None,
    cached_labels: Sequence[str] = (),
    alpha_clip: float = 0.0,
    rcond: float = 1.0e-12,
    min_improvement: float = 0.0,
) -> tuple[jnp.ndarray, jnp.ndarray, tuple[float, ...], tuple[int, ...], tuple[str, ...]]:
    """Apply a device-resident residual-equation correction over a small basis.

    Unlike the legacy post-coarse cleanup, this routine keeps candidate
    directions, cached operator actions, and the least-squares solve as JAX
    arrays. It is intended for fail-closed RHSMode=1/QI rescue attempts after a
    Krylov solve exposes the true remaining residual mode. Cached ``(U, A U)``
    columns from a previously built QI coarse space can be mixed with fresh
    residual-derived directions without reapplying the operator to those cached
    columns.
    """
    rhs = jnp.asarray(rhs, dtype=jnp.float64).reshape((-1,))
    x = jnp.asarray(x0, dtype=jnp.float64).reshape((-1,))
    residual = rhs - jnp.asarray(matvec(x), dtype=jnp.float64).reshape((-1,))
    residual_norm = float(jax.device_get(jnp.linalg.norm(residual)))
    history: list[float] = [residual_norm]
    accepted_counts: list[int] = []
    accepted_names: list[str] = []
    steps_use = max(0, int(steps))
    max_dirs_use = max(1, int(max_directions))
    alpha_clip_use = max(0.0, float(alpha_clip))
    rcond_use = max(0.0, float(rcond))
    min_improvement_use = max(0.0, float(min_improvement))
    n = int(rhs.size)

    cached_basis_jnp: jnp.ndarray | None = None
    cached_action_jnp: jnp.ndarray | None = None
    if cached_basis is not None and cached_operator_on_basis is not None:
        cached_basis_jnp = jnp.asarray(cached_basis, dtype=jnp.float64)
        cached_action_jnp = jnp.asarray(cached_operator_on_basis, dtype=jnp.float64)
        if (
            cached_basis_jnp.ndim != 2
            or cached_action_jnp.ndim != 2
            or int(cached_basis_jnp.shape[0]) != n
            or tuple(cached_basis_jnp.shape) != tuple(cached_action_jnp.shape)
        ):
            cached_basis_jnp = None
            cached_action_jnp = None
    cached_labels_use = tuple(str(label) for label in cached_labels)

    for _ in range(steps_use):
        names: list[str] = []
        basis_cols: list[jnp.ndarray] = []
        action_cols: list[jnp.ndarray] = []

        def _append_candidate(name: str, direction: jnp.ndarray, action: jnp.ndarray | None) -> None:
            if len(names) >= max_dirs_use:
                return
            vec = jnp.asarray(direction, dtype=jnp.float64).reshape((-1,))
            if int(vec.size) != n:
                return
            if action is None:
                act = jnp.asarray(matvec(vec), dtype=jnp.float64).reshape((-1,))
            else:
                act = jnp.asarray(action, dtype=jnp.float64).reshape((-1,))
            if int(act.size) != n:
                return
            norm = jnp.linalg.norm(vec)
            valid = jnp.logical_and(jnp.isfinite(norm), norm > 0.0)
            safe_norm = jnp.where(valid, norm, jnp.asarray(1.0, dtype=jnp.float64))
            q = jnp.where(valid, vec / safe_norm, jnp.zeros_like(vec))
            aq = jnp.where(valid, act / safe_norm, jnp.zeros_like(act))
            action_norm = jnp.linalg.norm(aq)
            valid = jnp.logical_and(valid, jnp.isfinite(action_norm))
            valid = jnp.logical_and(valid, action_norm > 0.0)
            valid = jnp.logical_and(valid, jnp.all(jnp.isfinite(q)))
            valid = jnp.logical_and(valid, jnp.all(jnp.isfinite(aq)))
            q = jnp.where(valid, q, jnp.zeros_like(q))
            aq = jnp.where(valid, aq, jnp.zeros_like(aq))
            names.append(str(name))
            basis_cols.append(q)
            action_cols.append(aq)

        if cached_basis_jnp is not None and cached_action_jnp is not None:
            cached_rank = min(int(cached_basis_jnp.shape[1]), max_dirs_use)
            for idx in range(cached_rank):
                label = cached_labels_use[idx] if idx < len(cached_labels_use) else f"cached_qi_{idx}"
                _append_candidate(
                    f"cached_qi:{label}",
                    cached_basis_jnp[:, idx],
                    cached_action_jnp[:, idx],
                )

        if direction_builder is not None and len(names) < max_dirs_use:
            for name, direction in tuple(direction_builder(residual)):
                if len(names) >= max_dirs_use:
                    break
                _append_candidate(str(name), direction, None)

        if not basis_cols:
            break
        basis = jnp.stack(basis_cols, axis=1)
        action_basis = jnp.stack(action_cols, axis=1)
        action_norms = jnp.linalg.norm(action_basis, axis=0)
        valid_cols = jnp.logical_and(jnp.isfinite(action_norms), action_norms > 0.0)
        valid_count = int(jax.device_get(jnp.sum(valid_cols.astype(jnp.int32))))
        if valid_count <= 0:
            break
        basis = jnp.where(valid_cols[None, :], basis, jnp.zeros_like(basis))
        action_basis = jnp.where(valid_cols[None, :], action_basis, jnp.zeros_like(action_basis))
        coeff = jnp.linalg.lstsq(
            action_basis,
            residual,
            rcond=rcond_use if rcond_use > 0.0 else None,
        )[0]
        coeff = jnp.where(valid_cols, coeff, jnp.zeros_like(coeff))
        coeff = jnp.nan_to_num(coeff, nan=0.0, posinf=0.0, neginf=0.0)
        if alpha_clip_use > 0.0:
            coeff = jnp.clip(coeff, -alpha_clip_use, alpha_clip_use)
        update = basis @ coeff
        residual_update = action_basis @ coeff
        trial_residual = residual - residual_update
        trial_norm_arr = jnp.linalg.norm(trial_residual)
        trial_norm = float(jax.device_get(trial_norm_arr))
        accept = bool(
            np.isfinite(float(trial_norm))
            and float(trial_norm) < float(residual_norm) * (1.0 - min_improvement_use)
        )
        if not accept:
            break
        x = x + update
        residual = trial_residual
        residual_norm = trial_norm
        history.append(float(residual_norm))
        valid_mask_np = np.asarray(jax.device_get(valid_cols), dtype=bool)
        accepted_counts.append(valid_count)
        accepted_names.extend(name for name, valid in zip(names, valid_mask_np, strict=True) if bool(valid))

    return x, residual, tuple(history), tuple(accepted_counts), tuple(accepted_names)


def _build_rhsmode1_pas_lite_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    safe: bool = True,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Lightweight PAS preconditioner: angular PAS block (if cheap) + x-coarse + collision diag.

    This preconditioner is intended for large PAS DKES/full-trajectory cases where the
    full PAS hybrid (line/xblock) preconditioner is expensive to build. We optionally
    apply a PAS-specific angular preconditioner (tokamak theta or 3D tz) only when the
    angular block size is modest, then follow with x-coarsening and a collision-diagonal
    smoothing pass.
    """
    angular_precond: Callable[[jnp.ndarray], jnp.ndarray] | None = None
    if _pas_tokamak_theta_preconditioner_applicable(op):
        angular_precond = _build_rhsmode1_pas_tokamak_theta_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )
    elif _pas_tz_preconditioner_applicable(op):
        tz_max_env = os.environ.get("SFINCS_JAX_PAS_LITE_TZ_MAX", "").strip()
        try:
            tz_max = int(tz_max_env) if tz_max_env else 256
        except ValueError:
            tz_max = 256
        tz_size = int(op.n_theta) * int(op.n_zeta)
        if tz_max > 0 and tz_size <= tz_max:
            angular_precond = _build_rhsmode1_pas_tz_preconditioner(
                op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
            )

    x_precond = _build_rhsmode1_xmg_preconditioner(
        op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
    )
    collision_precond = _build_rhsmode1_collision_preconditioner(
        op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
    )
    precond = x_precond
    if angular_precond is not None:
        precond = _compose_preconditioners(angular_precond, precond)
    precond = _compose_preconditioners(precond, collision_precond)
    return _safe_preconditioner(precond) if bool(safe) else precond


def _build_rhsmode1_pas_hybrid_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    safe: bool = True,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Hybrid PAS preconditioner: line solve + coarse-x correction + collision diagonal.

    This targets PAS DKES/full-trajectory cases where pure line or x-coarse preconditioners
    can stagnate. We apply a line preconditioner (theta or zeta), then a coarse-x additive
    correction (xmg), and finally the collision diagonal as a cheap smoothing pass.
    """
    line_precond: Callable[[jnp.ndarray], jnp.ndarray] | None = None
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    local_per_species = int(np.sum(nxi_for_x))
    line_size = int(local_per_species * int(op.n_theta))
    line_max_env = os.environ.get("SFINCS_JAX_PAS_HYBRID_LINE_MAX", "").strip()
    try:
        line_max = int(line_max_env) if line_max_env else 512
    except ValueError:
        line_max = 512
    if not line_max_env:
        # For small-Nzeta tokamak-like grids, allow line preconditioning by default.
        if int(op.n_zeta) <= 5 and int(op.n_theta) >= 8:
            line_max = max(int(line_max), 4096)
    if line_size <= line_max:
        if int(op.n_theta) >= int(op.n_zeta):
            line_precond = _build_rhsmode1_theta_line_preconditioner(
                op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
            )
        else:
            line_precond = _build_rhsmode1_zeta_line_preconditioner(
                op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
            )
    else:
        # Try a truncated-L (theta,zeta) block per x as a cheaper angular preconditioner.
        lmax_env = os.environ.get("SFINCS_JAX_PAS_HYBRID_LMAX", "").strip()
        has_er = op.fblock.er_xdot is not None or op.fblock.er_xidot is not None
        use_dkes_exb = bool(getattr(op.fblock.exb_theta, "use_dkes_exb_drift", False)) or bool(
            getattr(op.fblock.exb_zeta, "use_dkes_exb_drift", False)
        )
        needs_stronger_l = bool(has_er or use_dkes_exb)
        nz = int(op.n_theta) * int(op.n_zeta)
        try:
            if lmax_env:
                lmax = int(lmax_env)
            else:
                # The v3 Er xDot / xiDot terms couple ΔL=±2, so a truncated angular block that
                # only retains L=0 is often too weak. Default to keeping L=0..2 when these
                # terms are present (bounded by xblock_max below). For small angular grids
                # (tokamak-like cases), keep a few more L modes even without Er to improve robustness.
                lmax = 8 if (needs_stronger_l or nz <= 256) else 2
        except ValueError:
            lmax = 8 if (needs_stronger_l or nz <= 256) else 2
        xblock_max_env = os.environ.get("SFINCS_JAX_PAS_HYBRID_XBLOCK_MAX", "").strip()
        try:
            # PAS+Er runs need larger angular blocks to be effective; allow a larger default.
            # For small angular grids, allow a larger default so truncated-L blocks remain useful.
            xblock_max_default = 2048 if (needs_stronger_l or nz <= 256) else 256
            xblock_max = int(xblock_max_env) if xblock_max_env else xblock_max_default
        except ValueError:
            xblock_max = 2048 if (needs_stronger_l or nz <= 256) else 256
        if nz > 0:
            max_allowed = int(xblock_max // nz)
            if max_allowed > 0:
                lmax = min(int(lmax), max_allowed)
        block_size = int(max(0, lmax) * int(op.n_theta) * int(op.n_zeta))
        if lmax > 0 and block_size > 0 and block_size <= xblock_max:
            line_precond = _build_rhsmode1_xblock_tz_lmax_preconditioner(
                op=op,
                lmax=lmax,
                reduce_full=reduce_full,
                expand_reduced=expand_reduced,
            )
    x_precond: Callable[[jnp.ndarray], jnp.ndarray]
    if op.fblock.pas is not None and op.fblock.fp is None and op.fblock.er_xdot is not None:
        # The dense ddx matrices in the v3 Er xDot operator can be extremely ill-conditioned.
        # Prefer a stable x-upwind solve over explicit dense x-block inversions.
        x_precond = _build_rhsmode1_xupwind_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )
    else:
        x_precond = _build_rhsmode1_xmg_preconditioner(op=op, reduce_full=reduce_full, expand_reduced=expand_reduced)
    collision_precond = _build_rhsmode1_collision_preconditioner(
        op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
    )
    # Apply angular/line preconditioner (if enabled), then x-coarse correction, then collision smoothing.
    precond = x_precond
    if line_precond is not None:
        precond = _compose_preconditioners(line_precond, precond)
    precond = _compose_preconditioners(precond, collision_precond)
    # Guard against non-finite preconditioned vectors causing GMRES breakdown.
    #
    # Note: this wrapper is *nonlinear* (nan_to_num/clip). Avoid it when the preconditioner is
    # used as a building block inside other Krylov preconditioners (e.g. Schur), where linearity
    # matters for stability.
    return _safe_preconditioner(precond) if bool(safe) else precond


def _build_rhsmode1_pas_schur_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    safe: bool = True,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """PAS block-Schur preconditioner: (L,theta/zeta) coupling + x-coarsening + collisions.

    This targets tokamak/near-tokamak PAS RHSMode=1 systems where line/x-coarse
    preconditioners stagnate. We apply a stronger angular/L block preconditioner
    (pas_tokamak_theta or pas_tz), then an x-coarse correction (xmg or x-upwind),
    followed by the collision diagonal as a smoothing pass.
    """
    if _pas_tokamak_theta_preconditioner_applicable(op):
        angular_precond = _build_rhsmode1_pas_tokamak_theta_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )
    elif _pas_tz_preconditioner_applicable(op):
        angular_precond = _build_rhsmode1_pas_tz_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )
    else:
        angular_precond = _build_rhsmode1_pas_hybrid_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced, safe=False
        )

    if op.fblock.pas is not None and op.fblock.fp is None and op.fblock.er_xdot is not None:
        x_precond = _build_rhsmode1_xupwind_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )
    else:
        x_precond = _build_rhsmode1_xmg_preconditioner(op=op, reduce_full=reduce_full, expand_reduced=expand_reduced)

    collision_precond = _build_rhsmode1_collision_preconditioner(
        op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
    )
    precond = _compose_preconditioners(angular_precond, x_precond)
    precond = _compose_preconditioners(precond, collision_precond)
    return _safe_preconditioner(precond) if bool(safe) else precond


def _build_rhsmode1_species_block_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a RHSMode=1 preconditioner using full species blocks.

    For each species, solve a block over all (x,L,theta,zeta) points. This captures
    both angular and x/L coupling within each species while ignoring inter-species
    coupling, providing a much stronger preconditioner for PAS systems.
    """
    cache_key = _rhsmode1_precond_cache_key(op, "species_block")
    # Use block-size hint for mixed-precision selection on large species blocks.
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    local_per_species = int(np.sum(nxi_for_x))
    block_size_hint = int(local_per_species * int(op.n_theta) * int(op.n_zeta))
    precond_dtype = _precond_dtype(block_size_hint * block_size_hint)
    cached = _RHSMODE1_PRECOND_CACHE.get(cache_key)
    if cached is None:
        op_pc = op
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        local_per_species = int(np.sum(nxi_for_x))
        block_size = int(local_per_species * n_theta * n_zeta)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        idx_map = np.zeros((n_species, block_size), dtype=np.int32)
        block_inv = np.zeros((n_species, block_size, block_size), dtype=np.float64)

        for s in range(n_species):
            k = 0
            for ix in range(n_x):
                max_l = int(nxi_for_x[ix])
                for il in range(max_l):
                    for it in range(n_theta):
                        for iz in range(n_zeta):
                            idx_map[s, k] = int(
                                ((((s * n_x + ix) * n_l + il) * n_theta + it) * n_zeta + iz)
                            )
                            k += 1
            rep_idx = idx_map[s, :]
            chunk_cols = _precond_chunk_cols(total_size, int(rep_idx.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=rep_idx,
                row_idx=rep_idx,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            a = np.asarray(y_sub.T, dtype=np.float64)
            a = a + reg * np.eye(block_size, dtype=np.float64)
            try:
                inv = np.linalg.inv(a)
            except np.linalg.LinAlgError:
                inv = np.linalg.pinv(a, rcond=1e-12)
            if not np.all(np.isfinite(inv)):
                inv = np.linalg.pinv(a, rcond=1e-12)
            block_inv[s, :, :] = inv

        idx_map_jnp = jnp.asarray(idx_map, dtype=jnp.int32)
        flat_idx_jnp = idx_map_jnp.reshape((-1,))
        block_inv_jnp = jnp.asarray(block_inv, dtype=precond_dtype)

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondCache(
            idx_map_jnp=idx_map_jnp,
            flat_idx_jnp=flat_idx_jnp,
            block_inv_jnp=block_inv_jnp,
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_CACHE[cache_key] = cached

    block_inv_jnp = cached.block_inv_jnp
    flat_idx_jnp = cached.flat_idx_jnp
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp
    n_species = int(block_inv_jnp.shape[0])
    block_size = int(block_inv_jnp.shape[-1])

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        r_loc = r_full[flat_idx_jnp].reshape((n_species, block_size))
        z_loc = jnp.einsum("sij,sj->si", block_inv_jnp, r_loc)
        z_full = jnp.zeros_like(r_full)
        z_full = z_full.at[flat_idx_jnp].set(z_loc.reshape((-1,)), unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_species_xblock_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a RHSMode=1 preconditioner with a single species×x/L block per (theta,zeta).

    This includes inter-species coupling in the local (x,L) block, which is useful for
    FP collision cases where the field-particle terms couple species.
    """
    cache_key = _rhsmode1_precond_cache_key(op, "sxblock")
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    local_per_species = int(np.sum(nxi_for_x))
    block_size = int(int(op.n_species) * local_per_species)
    precond_dtype = _precond_dtype(block_size * block_size)
    cached = _RHSMODE1_PRECOND_GLOBAL_CACHE.get(cache_key)
    if cached is None:
        op_pc = op
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        rep_idx: list[int] = []
        for s in range(n_species):
            for ix in range(n_x):
                max_l = int(nxi_for_x[ix])
                for il in range(max_l):
                    f_idx = ((((s * n_x + ix) * n_l + il) * n_theta + 0) * n_zeta + 0)
                    rep_idx.append(int(f_idx))
        rep_idx_np = np.asarray(rep_idx, dtype=np.int32)
        chunk_cols = _precond_chunk_cols(total_size, int(rep_idx_np.shape[0]))
        y_sub = _matvec_submatrix(
            op_pc,
            col_idx=rep_idx_np,
            row_idx=rep_idx_np,
            total_size=total_size,
            chunk_cols=chunk_cols,
        )
        a = np.asarray(y_sub.T, dtype=np.float64)
        a = a + reg * np.eye(block_size, dtype=np.float64)
        try:
            inv = np.linalg.inv(a)
        except np.linalg.LinAlgError:
            inv = np.linalg.pinv(a, rcond=1e-12)
        if not np.all(np.isfinite(inv)):
            inv = np.linalg.pinv(a, rcond=1e-12)

        idx_map = np.zeros((n_theta, n_zeta, block_size), dtype=np.int32)
        for it in range(n_theta):
            for iz in range(n_zeta):
                k = 0
                for s in range(n_species):
                    for ix in range(n_x):
                        max_l = int(nxi_for_x[ix])
                        for il in range(max_l):
                            idx_map[it, iz, k] = int(
                                ((((s * n_x + ix) * n_l + il) * n_theta + it) * n_zeta + iz)
                            )
                            k += 1

        idx_map_jnp = jnp.asarray(idx_map, dtype=jnp.int32)
        flat_idx_jnp = idx_map_jnp.reshape((-1,))
        block_inv_jnp = jnp.asarray(inv, dtype=precond_dtype)

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondGlobalCache(
            idx_map_jnp=idx_map_jnp,
            flat_idx_jnp=flat_idx_jnp,
            block_inv_jnp=block_inv_jnp,
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_GLOBAL_CACHE[cache_key] = cached

    block_inv_jnp = cached.block_inv_jnp
    flat_idx_jnp = cached.flat_idx_jnp
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        r_loc = r_full[flat_idx_jnp].reshape((int(op.n_theta), int(op.n_zeta), block_size))
        z_loc = jnp.einsum("ij,tzj->tzi", block_inv_jnp, r_loc)
        z_full = jnp.zeros_like(r_full)
        z_full = z_full.at[flat_idx_jnp].set(z_loc.reshape((-1,)), unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_xblock_tz_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a RHSMode=1 preconditioner using full (theta,zeta) blocks per x.

    For each species and each x, solve the block over all (L,theta,zeta) points.
    This captures angular coupling while retaining x/L coupling without assembling
    full species blocks.
    """
    cache_key = _rhsmode1_precond_cache_key(op, "xblock_tz")
    cached = _RHSMODE1_PRECOND_LIST_CACHE.get(cache_key)
    if cached is None:
        op_pc = op
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        max_l = int(np.max(nxi_for_x)) if nxi_for_x.size else 0
        max_block_size = int(max_l * n_theta * n_zeta)
        precond_dtype = _precond_dtype(max_block_size * max_block_size)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)
        pas_max_cols = None
        if op.fblock.pas is not None:
            pas_cols_env = os.environ.get("SFINCS_JAX_PRECOND_PAS_MAX_COLS", "").strip()
            try:
                if pas_cols_env:
                    pas_max_cols = int(pas_cols_env)
                else:
                    tz_size = int(n_theta) * int(n_zeta)
                    pas_max_cols = 256 if tz_size <= 256 else 64
            except ValueError:
                tz_size = int(n_theta) * int(n_zeta)
                pas_max_cols = 256 if tz_size <= 256 else 64

        block_inv_list: list[jnp.ndarray] = []
        block_slices: list[tuple[int, int]] = []

        for s in range(n_species):
            for ix in range(n_x):
                max_l = int(nxi_for_x[ix])
                block_size = int(max_l * n_theta * n_zeta)
                start = int((((s * n_x + ix) * n_l) * n_theta) * n_zeta)
                if block_size <= 0:
                    continue
                rep_idx = np.arange(start, start + block_size, dtype=np.int32)
                chunk_cols = _precond_chunk_cols(total_size, int(rep_idx.shape[0]))
                if pas_max_cols is not None and block_size >= 256:
                    chunk_cols = min(chunk_cols, pas_max_cols)
                y_sub = _matvec_submatrix(
                    op_pc,
                    col_idx=rep_idx,
                    row_idx=rep_idx,
                    total_size=total_size,
                    chunk_cols=chunk_cols,
                )
                a = np.asarray(y_sub.T, dtype=np.float64)
                a = a + reg * np.eye(block_size, dtype=np.float64)
                try:
                    inv = np.linalg.inv(a)
                except np.linalg.LinAlgError:
                    inv = np.linalg.pinv(a, rcond=1e-12)
                if not np.all(np.isfinite(inv)):
                    inv = np.linalg.pinv(a, rcond=1e-12)
                block_inv_list.append(jnp.asarray(inv, dtype=precond_dtype))
                block_slices.append((start, block_size))

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondListCache(
            block_inv_list=tuple(block_inv_list),
            block_slices=tuple(block_slices),
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_LIST_CACHE[cache_key] = cached

    block_inv_list = cached.block_inv_list
    block_slices = cached.block_slices
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp
    precond_dtype = block_inv_list[0].dtype if block_inv_list else _precond_dtype()

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        z_full = jnp.zeros_like(r_full)
        for inv, (start, block_size) in zip(block_inv_list, block_slices, strict=True):
            r_loc = r_full[start : start + block_size]
            z_loc = inv @ r_loc
            z_full = z_full.at[start : start + block_size].set(z_loc, unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_xblock_tz_lmax_preconditioner(
    *,
    op: V3FullSystemOperator,
    lmax: int,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a RHSMode=1 preconditioner using truncated-L (theta,zeta) blocks per x.

    Uses only the lowest L<=lmax modes per x to reduce block size while retaining
    angular coupling. Higher-L rows are left unpreconditioned (identity).
    """
    lmax = int(lmax)
    if lmax <= 0:
        return _build_rhsmode1_xblock_tz_preconditioner(op=op, reduce_full=reduce_full, expand_reduced=expand_reduced)
    cache_key = _rhsmode1_precond_cache_key(op, f"xblock_tz_lmax_{lmax}")
    cached = _RHSMODE1_PRECOND_LIST_CACHE.get(cache_key)
    if cached is None:
        op_pc = op
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        max_l = int(np.max(nxi_for_x)) if nxi_for_x.size else 0
        max_l = min(max_l, lmax)
        max_block_size = int(max_l * n_theta * n_zeta)
        precond_dtype = _precond_dtype(max_block_size * max_block_size)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)
        pas_max_cols = None
        if op.fblock.pas is not None:
            pas_cols_env = os.environ.get("SFINCS_JAX_PRECOND_PAS_MAX_COLS", "").strip()
            try:
                pas_max_cols = int(pas_cols_env) if pas_cols_env else 64
            except ValueError:
                pas_max_cols = 64

        block_inv_list: list[jnp.ndarray] = []
        block_slices: list[tuple[int, int]] = []

        for s in range(n_species):
            for ix in range(n_x):
                max_lx = min(int(nxi_for_x[ix]), lmax)
                block_size = int(max_lx * n_theta * n_zeta)
                start = int((((s * n_x + ix) * n_l) * n_theta) * n_zeta)
                if block_size <= 0:
                    continue
                rep_idx = np.arange(start, start + block_size, dtype=np.int32)
                chunk_cols = _precond_chunk_cols(total_size, int(rep_idx.shape[0]))
                if pas_max_cols is not None and block_size >= 256:
                    chunk_cols = min(chunk_cols, pas_max_cols)
                y_sub = _matvec_submatrix(
                    op_pc,
                    col_idx=rep_idx,
                    row_idx=rep_idx,
                    total_size=total_size,
                    chunk_cols=chunk_cols,
                )
                a = np.asarray(y_sub.T, dtype=np.float64)
                a = a + reg * np.eye(block_size, dtype=np.float64)
                try:
                    inv = np.linalg.inv(a)
                except np.linalg.LinAlgError:
                    inv = np.linalg.pinv(a, rcond=1e-12)
                if not np.all(np.isfinite(inv)):
                    inv = np.linalg.pinv(a, rcond=1e-12)
                block_inv_list.append(jnp.asarray(inv, dtype=precond_dtype))
                block_slices.append((start, block_size))

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondListCache(
            block_inv_list=tuple(block_inv_list),
            block_slices=tuple(block_slices),
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_LIST_CACHE[cache_key] = cached

    block_inv_list = cached.block_inv_list
    block_slices = cached.block_slices
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp
    precond_dtype = block_inv_list[0].dtype if block_inv_list else _precond_dtype()

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        z_full = jnp.asarray(r_full, dtype=precond_dtype)
        for inv, (start, block_size) in zip(block_inv_list, block_slices, strict=True):
            r_loc = r_full[start : start + block_size]
            z_loc = inv @ r_loc
            z_full = z_full.at[start : start + block_size].set(z_loc, unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _rhsmode1_xblock_sparse_lu_default_max(op: object, *, build_jax_factors: bool) -> int:
    """Default exact-LU cap for RHSMode=1 x-block sparse preconditioners."""
    fblock = getattr(op, "fblock", None)
    return _rhs1_xblock_sparse_host_policy.rhs1_xblock_sparse_lu_default_max(
        has_fp=getattr(fblock, "fp", None) is not None,
        has_pas=getattr(fblock, "pas", None) is not None,
        build_jax_factors=bool(build_jax_factors),
    )


def _build_rhsmode1_xblock_tz_sparse_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    build_jax_factors: bool,
    preconditioner_species: int,
    preconditioner_xi: int,
    drop_tol: float,
    drop_rel: float,
    ilu_drop_tol: float,
    fill_factor: float,
    force_assembled_host_fp: bool = False,
    emit: Callable[[int, str], None] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Sparse per-x preconditioner for large FP RHSMode=1 systems.

    This is a closer analogue to v3's default matrix preconditioner when
    ``preconditioner_x > 0``: retain the full local (theta,zeta,L) coupling
    inside each x-block, but drop inter-x coupling by factorizing each
    per-(species,x) block independently with sparse ILU/LU.
    """
    row_cap_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_SPARSE_ROW_NNZ_MAX", "").strip()
    try:
        row_cap = int(row_cap_env) if row_cap_env else 64
    except ValueError:
        row_cap = 64
    row_cap = max(0, int(row_cap))
    jax_factor_format_env = (
        os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_SPARSE_JAX_FACTOR_FORMAT", "padded")
        .strip()
        .lower()
        .replace("-", "_")
    )
    xblock_jax_factor_format = (
        "csr"
        if jax_factor_format_env in {"csr", "compact", "compact_csr", "ragged_csr"}
        else "padded"
    )
    jax_factor_apply_env = (
        os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_SPARSE_JAX_FACTOR_APPLY", "exact")
        .strip()
        .lower()
        .replace("-", "_")
    )
    xblock_jax_factor_apply = (
        "diagonal"
        if jax_factor_apply_env in {"diag", "diagonal", "jacobi", "factor_diag", "factor_diagonal"}
        else "identity"
        if jax_factor_apply_env in {"identity", "none", "skip"}
        else "upper"
        if jax_factor_apply_env in {"upper", "upper_only", "u", "u_only"}
        else "lower"
        if jax_factor_apply_env in {"lower", "lower_only", "l", "l_only"}
        else "exact"
    )
    compact_row_cap_env = os.environ.get(
        "SFINCS_JAX_RHSMODE1_XBLOCK_SPARSE_COMPACT_ROW_NNZ_MAX",
        "",
    ).strip()
    try:
        compact_row_cap = int(compact_row_cap_env) if compact_row_cap_env else 0
    except ValueError:
        compact_row_cap = 0
    compact_row_cap = max(0, int(compact_row_cap))
    n_species = int(op.n_species)
    n_x = int(op.n_x)
    n_l = int(op.n_xi)
    n_theta = int(op.n_theta)
    n_zeta = int(op.n_zeta)
    total_size = int(op.total_size)
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    block_size_max = int(n_l * n_theta * n_zeta)
    default_lu_max = _rhsmode1_xblock_sparse_lu_default_max(op, build_jax_factors=build_jax_factors)
    lu_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_SPARSE_LU_MAX", "").strip()
    try:
        lu_max = int(lu_max_env) if lu_max_env else default_lu_max
    except ValueError:
        lu_max = default_lu_max
    lu_max = max(0, int(lu_max))
    lower_fill_env = os.environ.get("SFINCS_JAX_RHSMODE1_XBLOCK_PC_LOWER_FILL", "").strip()
    lower_fill_drop_tol_env = os.environ.get(
        "SFINCS_JAX_RHSMODE1_XBLOCK_PC_LOWER_FILL_DROP_TOL",
        "",
    ).strip()
    lower_fill_drop_rel_env = os.environ.get(
        "SFINCS_JAX_RHSMODE1_XBLOCK_PC_LOWER_FILL_DROP_REL",
        "",
    ).strip()
    lower_fill_ilu_drop_tol_env = os.environ.get(
        "SFINCS_JAX_RHSMODE1_XBLOCK_PC_LOWER_FILL_ILU_DROP_TOL",
        "",
    ).strip()
    lower_fill_factor_env = os.environ.get(
        "SFINCS_JAX_RHSMODE1_XBLOCK_PC_LOWER_FILL_FACTOR",
        "",
    ).strip()
    lower_fill_row_cap_env = os.environ.get(
        "SFINCS_JAX_RHSMODE1_XBLOCK_PC_LOWER_FILL_ROW_NNZ_MAX",
        "",
    ).strip()
    lower_fill_compact_row_cap_env = os.environ.get(
        "SFINCS_JAX_RHSMODE1_XBLOCK_PC_LOWER_FILL_COMPACT_ROW_NNZ_MAX",
        "",
    ).strip()
    lower_fill_max_block_env = os.environ.get(
        "SFINCS_JAX_RHSMODE1_XBLOCK_PC_LOWER_FILL_MAX_BLOCK_SIZE",
        "",
    ).strip()
    host_block_max_env = os.environ.get(
        "SFINCS_JAX_RHSMODE1_XBLOCK_SPARSE_HOST_BLOCK_MAX",
        "",
    ).strip()
    skipped_diag_fallback = _rhs1_bool_env(
        "SFINCS_JAX_RHSMODE1_XBLOCK_SPARSE_HOST_SKIPPED_DIAG_FALLBACK",
        default=False,
    )
    skipped_diag_floor = _rhs1_float_env(
        "SFINCS_JAX_RHSMODE1_XBLOCK_SPARSE_HOST_SKIPPED_DIAG_FLOOR",
        default=1.0e-10,
        minimum=0.0,
    )
    lower_fill_mode, lower_fill_ignored_env = _rhs1_xblock_policy.rhs1_xblock_lower_fill_mode(lower_fill_env)

    def _local_factor_candidate(block_size: int) -> _rhs1_xblock_policy.RHS1XBlockLocalSolveCandidate:
        return _rhs1_xblock_policy.rhs1_xblock_local_solve_candidate(
            block_size=int(block_size),
            lu_max=int(lu_max),
            lower_fill_env_value=lower_fill_env,
            drop_tol_env_value=str(drop_tol),
            drop_rel_env_value=str(drop_rel),
            ilu_drop_tol_env_value=str(ilu_drop_tol),
            fill_factor_env_value=str(fill_factor),
            row_nnz_cap_env_value=str(row_cap),
            compact_row_nnz_cap_env_value=str(compact_row_cap),
            lower_fill_drop_tol_env_value=lower_fill_drop_tol_env,
            lower_fill_drop_rel_env_value=lower_fill_drop_rel_env,
            lower_fill_ilu_drop_tol_env_value=lower_fill_ilu_drop_tol_env,
            lower_fill_factor_env_value=lower_fill_factor_env,
            lower_fill_row_nnz_cap_env_value=lower_fill_row_cap_env,
            lower_fill_compact_row_nnz_cap_env_value=lower_fill_compact_row_cap_env,
            lower_fill_max_block_size_env_value=lower_fill_max_block_env,
        )

    cache_key = (
        *_rhsmode1_precond_cache_key(op, "xblock_tz_sparse"),
        bool(build_jax_factors),
        float(drop_tol),
        float(drop_rel),
        float(ilu_drop_tol),
        float(fill_factor),
        int(row_cap),
        str(xblock_jax_factor_format) if build_jax_factors else "host",
        int(compact_row_cap) if build_jax_factors and xblock_jax_factor_format == "csr" else 0,
        str(xblock_jax_factor_apply) if build_jax_factors else "host",
        int(lu_max),
        bool(force_assembled_host_fp),
        str(lower_fill_mode),
        bool(lower_fill_ignored_env),
        lower_fill_drop_tol_env,
        lower_fill_drop_rel_env,
        lower_fill_ilu_drop_tol_env,
        lower_fill_factor_env,
        lower_fill_row_cap_env,
        lower_fill_compact_row_cap_env,
        lower_fill_max_block_env,
        host_block_max_env if not build_jax_factors else "",
        bool(skipped_diag_fallback) if not build_jax_factors else False,
        float(skipped_diag_floor) if not build_jax_factors else 0.0,
    )

    if build_jax_factors:
        if xblock_jax_factor_format == "csr":
            cached = _RHSMODE1_SPARSE_XBLOCK_CSR_PRECOND_CACHE.get(cache_key)
        else:
            cached = _RHSMODE1_SPARSE_XBLOCK_PRECOND_CACHE.get(cache_key)
    else:
        cached = _RHSMODE1_SPARSE_XBLOCK_HOST_PRECOND_CACHE.get(cache_key)

    if cached is None:
        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        assembled_host_fp = bool(
            (
                bool(force_assembled_host_fp)
                and (not bool(build_jax_factors))
                and int(op.rhs_mode) == 1
                and (not bool(op.include_phi1))
                and op.fblock.fp is not None
                and op.fblock.pas is None
                and _rhsmode1_fp_xblock_species_decoupled_for_host_assembly(
                    op=op,
                    preconditioner_species=preconditioner_species,
                )
                and int(preconditioner_xi) == 1
                and (not bool(op.point_at_x0))
            )
            or _rhsmode1_fp_xblock_assembled_host_allowed(
                op=op,
                preconditioner_species=preconditioner_species,
                preconditioner_xi=preconditioner_xi,
                use_implicit=build_jax_factors,
            )
        )
        assembled_host_cache = _get_rhsmode1_fp_xblock_assembled_host_cache(op=op) if assembled_host_fp else None

        if build_jax_factors and xblock_jax_factor_format == "csr":
            perm_r_blocks: list[np.ndarray] = []
            inv_perm_c_blocks: list[np.ndarray] = []
            upper_diag_blocks: list[np.ndarray] = []
            lower_indptr_parts: list[np.ndarray] = []
            lower_indices_parts: list[np.ndarray] = []
            lower_val_parts: list[np.ndarray] = []
            upper_indptr_parts: list[np.ndarray] = []
            upper_indices_parts: list[np.ndarray] = []
            upper_val_parts: list[np.ndarray] = []
            lower_nnz_total = 0
            upper_nnz_total = 0
            csr_index_limit = int(np.iinfo(np.int32).max)

            for s in range(n_species):
                for ix in range(n_x):
                    n_lx = int(nxi_for_x[ix])
                    block_size = int(n_lx * n_theta * n_zeta)
                    start = int((((s * n_x + ix) * n_l) * n_theta) * n_zeta)

                    perm_r_full = np.arange(block_size_max, dtype=np.int32)
                    inv_perm_c_full = np.arange(block_size_max, dtype=np.int32)
                    upper_diag_full = np.ones((block_size_max,), dtype=np.float64)
                    lower_indptr_full = np.empty((block_size_max + 1,), dtype=np.int32)
                    upper_indptr_full = np.empty((block_size_max + 1,), dtype=np.int32)
                    lower_indptr_full[0] = int(lower_nnz_total)
                    upper_indptr_full[0] = int(upper_nnz_total)

                    fac_cache = None
                    if block_size > 0:
                        block_slice = slice(start, start + block_size)

                        def _mv_block(v_block: jnp.ndarray, *, _block_slice=block_slice) -> jnp.ndarray:
                            x_full = jnp.zeros((total_size,), dtype=v_block.dtype)
                            x_full = x_full.at[_block_slice].set(v_block)
                            y_full = apply_v3_full_system_operator_cached(op, x_full)
                            return y_full[_block_slice]

                        block_cache_key = (cache_key, "csr", int(s), int(ix), int(block_size))
                        local_candidate = _local_factor_candidate(block_size)
                        block_compact_row_cap = int(local_candidate.tuning.compact_row_nnz_cap)
                        if local_candidate.lower_fill and emit is not None:
                            emit(
                                1,
                                "xblock_sparse_csr: lower-fill local factor "
                                f"(species={int(s)} x={int(ix)} size={int(block_size)} "
                                f"drop_tol={local_candidate.tuning.ilu_drop_tol:.1e} "
                                f"fill={local_candidate.tuning.fill_factor:.1f} "
                                f"row_cap={int(local_candidate.tuning.row_nnz_cap)} "
                                f"compact_row_cap={int(block_compact_row_cap)})",
                            )
                        try:
                            _build_sparse_ilu_from_matvec(
                                matvec=_mv_block,
                                n=int(block_size),
                                dtype=jnp.float64,
                                cache_key=block_cache_key,
                                drop_tol=local_candidate.tuning.drop_tol,
                                drop_rel=local_candidate.tuning.drop_rel,
                                ilu_drop_tol=local_candidate.tuning.ilu_drop_tol,
                                fill_factor=local_candidate.tuning.fill_factor,
                                build_dense_factors=False,
                                build_jax_factors=False,
                                build_ilu=True,
                                store_dense=False,
                                factorization=local_candidate.factorization,
                                row_nnz_cap=0,
                                emit=emit,
                            )
                            fac_cache = _RHSMODE1_SPARSE_ILU_CACHE.get(block_cache_key)
                        except Exception as exc:  # noqa: BLE001
                            fac_cache = None
                            if emit is not None:
                                emit(
                                    1,
                                    "xblock_sparse_csr: factorization failed for block "
                                    f"(species={int(s)} x={int(ix)} size={int(block_size)}) "
                                    f"({type(exc).__name__}: {exc})",
                                )

                    fac = None if fac_cache is None else fac_cache.ilu
                    if fac is not None:
                        perm_r = np.asarray(fac.perm_r, dtype=np.int32)
                        perm_c = np.asarray(fac.perm_c, dtype=np.int32)
                        inv_perm_c = np.argsort(perm_c).astype(np.int32, copy=False)
                        perm_r_full[:block_size] = perm_r
                        inv_perm_c_full[:block_size] = inv_perm_c

                        l_csr = fac.L.tocsr()
                        u_csr = fac.U.tocsr()
                        for i in range(int(block_size)):
                            rs = int(l_csr.indptr[i])
                            re = int(l_csr.indptr[i + 1])
                            cols = l_csr.indices[rs:re]
                            vals = l_csr.data[rs:re]
                            mask = cols < i
                            cols_l = cols[mask].astype(np.int32, copy=False)
                            vals_l = vals[mask].astype(np.float64, copy=False)
                            if block_compact_row_cap > 0 and int(cols_l.size) > int(block_compact_row_cap):
                                sel = np.argpartition(np.abs(vals_l), -int(block_compact_row_cap))[
                                    -int(block_compact_row_cap) :
                                ]
                                cols_l = cols_l[sel]
                                vals_l = vals_l[sel]
                            if cols_l.size:
                                order = np.argsort(cols_l)
                                cols_l = cols_l[order]
                                vals_l = vals_l[order]
                                lower_indices_parts.append(cols_l)
                                lower_val_parts.append(vals_l)
                                lower_nnz_total += int(cols_l.size)
                                if lower_nnz_total > csr_index_limit:
                                    raise MemoryError("compact x-block lower factor exceeds int32 CSR index capacity")
                            lower_indptr_full[i + 1] = int(lower_nnz_total)

                            rs_u = int(u_csr.indptr[i])
                            re_u = int(u_csr.indptr[i + 1])
                            cols_u_all = u_csr.indices[rs_u:re_u]
                            vals_u_all = u_csr.data[rs_u:re_u]
                            diag_mask = cols_u_all == i
                            if np.any(diag_mask):
                                upper_diag_full[i] = float(vals_u_all[diag_mask][0])
                            cols_u = cols_u_all[cols_u_all > i].astype(np.int32, copy=False)
                            vals_u = vals_u_all[cols_u_all > i].astype(np.float64, copy=False)
                            if block_compact_row_cap > 0 and int(cols_u.size) > int(block_compact_row_cap):
                                sel = np.argpartition(np.abs(vals_u), -int(block_compact_row_cap))[
                                    -int(block_compact_row_cap) :
                                ]
                                cols_u = cols_u[sel]
                                vals_u = vals_u[sel]
                            if cols_u.size:
                                order = np.argsort(cols_u)
                                cols_u = cols_u[order]
                                vals_u = vals_u[order]
                                upper_indices_parts.append(cols_u)
                                upper_val_parts.append(vals_u)
                                upper_nnz_total += int(cols_u.size)
                                if upper_nnz_total > csr_index_limit:
                                    raise MemoryError("compact x-block upper factor exceeds int32 CSR index capacity")
                            upper_indptr_full[i + 1] = int(upper_nnz_total)

                        bad_diag = ~np.isfinite(upper_diag_full[:block_size]) | (upper_diag_full[:block_size] == 0.0)
                        if np.any(bad_diag):
                            upper_diag_full[np.flatnonzero(bad_diag)] = 1.0
                    elif emit is not None and block_size > 0:
                        emit(
                            1,
                            "xblock_sparse_csr: missing factor for block "
                            f"(species={int(s)} x={int(ix)} size={int(block_size)}); using identity",
                        )

                    if fac is None:
                        lower_indptr_full[1:] = int(lower_nnz_total)
                        upper_indptr_full[1:] = int(upper_nnz_total)
                    elif block_size < block_size_max:
                        lower_indptr_full[block_size + 1 :] = int(lower_nnz_total)
                        upper_indptr_full[block_size + 1 :] = int(upper_nnz_total)

                    perm_r_blocks.append(perm_r_full)
                    inv_perm_c_blocks.append(inv_perm_c_full)
                    upper_diag_blocks.append(upper_diag_full)
                    lower_indptr_parts.append(lower_indptr_full)
                    upper_indptr_parts.append(upper_indptr_full)

            lower_indices_np = (
                np.concatenate(lower_indices_parts).astype(np.int32, copy=False)
                if lower_indices_parts
                else np.zeros((0,), dtype=np.int32)
            )
            lower_val_np = (
                np.concatenate(lower_val_parts).astype(np.float64, copy=False)
                if lower_val_parts
                else np.zeros((0,), dtype=np.float64)
            )
            upper_indices_np = (
                np.concatenate(upper_indices_parts).astype(np.int32, copy=False)
                if upper_indices_parts
                else np.zeros((0,), dtype=np.int32)
            )
            upper_val_np = (
                np.concatenate(upper_val_parts).astype(np.float64, copy=False)
                if upper_val_parts
                else np.zeros((0,), dtype=np.float64)
            )
            lower_indptr_np = np.concatenate(lower_indptr_parts).astype(np.int32, copy=False)
            upper_indptr_np = np.concatenate(upper_indptr_parts).astype(np.int32, copy=False)
            perm_r_np = np.stack(perm_r_blocks, axis=0).reshape((n_species, n_x, block_size_max))
            inv_perm_c_np = np.stack(inv_perm_c_blocks, axis=0).reshape((n_species, n_x, block_size_max))
            upper_diag_np = np.stack(upper_diag_blocks, axis=0).reshape((n_species, n_x, block_size_max))
            factor_nbytes = int(
                lower_indptr_np.nbytes
                + upper_indptr_np.nbytes
                + lower_indices_np.nbytes
                + upper_indices_np.nbytes
                + lower_val_np.nbytes
                + upper_val_np.nbytes
                + perm_r_np.nbytes
                + inv_perm_c_np.nbytes
                + upper_diag_np.nbytes
            )

            extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
            extra_inv_jnp: jnp.ndarray | None = None
            if extra_size > 0:
                chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
                y_sub = _matvec_submatrix(
                    op,
                    col_idx=extra_idx_np,
                    row_idx=extra_idx_np,
                    total_size=total_size,
                    chunk_cols=chunk_cols,
                )
                ee = np.asarray(y_sub.T, dtype=np.float64)
                ee = ee + np.float64(reg_val) * np.eye(extra_size, dtype=np.float64)
                try:
                    ee_inv = np.linalg.inv(ee)
                except np.linalg.LinAlgError:
                    ee_inv = np.linalg.pinv(ee, rcond=1e-12)
                if not np.all(np.isfinite(ee_inv)):
                    ee_inv = np.linalg.pinv(ee, rcond=1e-12)
                extra_inv_jnp = jnp.asarray(ee_inv, dtype=jnp.float64)

            cached = _RHSMode1SparseXBlockCSRPrecondCache(
                perm_r_sx=jnp.asarray(perm_r_np, dtype=jnp.int32),
                inv_perm_c_sx=jnp.asarray(inv_perm_c_np, dtype=jnp.int32),
                lower_indptr=jnp.asarray(lower_indptr_np, dtype=jnp.int32),
                lower_indices=jnp.asarray(lower_indices_np, dtype=jnp.int32),
                lower_val=jnp.asarray(lower_val_np, dtype=jnp.float64),
                upper_indptr=jnp.asarray(upper_indptr_np, dtype=jnp.int32),
                upper_indices=jnp.asarray(upper_indices_np, dtype=jnp.int32),
                upper_val=jnp.asarray(upper_val_np, dtype=jnp.float64),
                upper_diag_sx=jnp.asarray(upper_diag_np, dtype=jnp.float64),
                extra_idx_jnp=extra_idx_jnp,
                extra_inv_jnp=extra_inv_jnp,
                lower_nnz=int(lower_indices_np.size),
                upper_nnz=int(upper_indices_np.size),
                nbytes_estimate=int(factor_nbytes),
            )
            _RHSMODE1_SPARSE_XBLOCK_CSR_PRECOND_CACHE[cache_key] = cached
            if emit is not None:
                emit(
                    1,
                    "xblock_sparse_csr: built compact JAX factors "
                    f"(lower_nnz={int(lower_indices_np.size)} upper_nnz={int(upper_indices_np.size)} "
                    f"nbytes={int(factor_nbytes)})",
                )
        elif build_jax_factors:
            perm_r_blocks: list[np.ndarray] = []
            inv_perm_c_blocks: list[np.ndarray] = []
            lower_idx_blocks: list[np.ndarray] = []
            lower_val_blocks: list[np.ndarray] = []
            upper_idx_blocks: list[np.ndarray] = []
            upper_val_blocks: list[np.ndarray] = []
            upper_diag_blocks: list[np.ndarray] = []
            max_lower_global = 0
            max_upper_global = 0

            for s in range(n_species):
                for ix in range(n_x):
                    n_lx = int(nxi_for_x[ix])
                    block_size = int(n_lx * n_theta * n_zeta)
                    start = int((((s * n_x + ix) * n_l) * n_theta) * n_zeta)

                    perm_r_full = np.arange(block_size_max, dtype=np.int32)
                    inv_perm_c_full = np.arange(block_size_max, dtype=np.int32)
                    lower_idx_full = np.zeros((block_size_max, 0), dtype=np.int32)
                    lower_val_full = np.zeros((block_size_max, 0), dtype=np.float64)
                    upper_idx_full = np.zeros((block_size_max, 0), dtype=np.int32)
                    upper_val_full = np.zeros((block_size_max, 0), dtype=np.float64)
                    upper_diag_full = np.ones((block_size_max,), dtype=np.float64)

                    if block_size > 0:
                        block_slice = slice(start, start + block_size)

                        def _mv_block(v_block: jnp.ndarray, *, _block_slice=block_slice) -> jnp.ndarray:
                            x_full = jnp.zeros((total_size,), dtype=v_block.dtype)
                            x_full = x_full.at[_block_slice].set(v_block)
                            y_full = apply_v3_full_system_operator_cached(op, x_full)
                            return y_full[_block_slice]

                        block_cache_key = (cache_key, int(s), int(ix), int(block_size))
                        local_candidate = _local_factor_candidate(block_size)
                        if local_candidate.lower_fill and emit is not None:
                            emit(
                                1,
                                "xblock_sparse: lower-fill local factor "
                                f"(species={int(s)} x={int(ix)} size={int(block_size)} "
                                f"drop_tol={local_candidate.tuning.ilu_drop_tol:.1e} "
                                f"fill={local_candidate.tuning.fill_factor:.1f} "
                                f"row_cap={int(local_candidate.tuning.row_nnz_cap)})",
                            )
                        try:
                            _build_sparse_ilu_from_matvec(
                                matvec=_mv_block,
                                n=int(block_size),
                                dtype=jnp.float64,
                                cache_key=block_cache_key,
                                drop_tol=local_candidate.tuning.drop_tol,
                                drop_rel=local_candidate.tuning.drop_rel,
                                ilu_drop_tol=local_candidate.tuning.ilu_drop_tol,
                                fill_factor=local_candidate.tuning.fill_factor,
                                build_dense_factors=False,
                                build_jax_factors=True,
                                build_ilu=True,
                                store_dense=False,
                                factorization=local_candidate.factorization,
                                row_nnz_cap=int(local_candidate.tuning.row_nnz_cap),
                                emit=emit,
                            )
                            fac_cache = _RHSMODE1_SPARSE_ILU_CACHE.get(block_cache_key)
                        except Exception as exc:  # noqa: BLE001
                            fac_cache = None
                            if emit is not None:
                                emit(
                                    1,
                                    "xblock_sparse: factorization failed for block "
                                    f"(species={int(s)} x={int(ix)} size={int(block_size)}) "
                                    f"({type(exc).__name__}: {exc})",
                                )
                        if fac_cache is not None:
                            perm_r = fac_cache.perm_r
                            inv_perm_c = fac_cache.inv_perm_c
                            lower_idx = fac_cache.lower_idx
                            lower_val = fac_cache.lower_val
                            upper_idx = fac_cache.upper_idx
                            upper_val = fac_cache.upper_val
                            upper_diag = fac_cache.upper_diag
                            if (
                                perm_r is not None
                                and inv_perm_c is not None
                                and lower_idx is not None
                                and lower_val is not None
                                and upper_idx is not None
                                and upper_val is not None
                                and upper_diag is not None
                            ):
                                perm_r_np = np.asarray(perm_r, dtype=np.int32)
                                inv_perm_c_np = np.asarray(inv_perm_c, dtype=np.int32)
                                lower_idx_np = np.asarray(lower_idx, dtype=np.int32)
                                lower_val_np = np.asarray(lower_val, dtype=np.float64)
                                upper_idx_np = np.asarray(upper_idx, dtype=np.int32)
                                upper_val_np = np.asarray(upper_val, dtype=np.float64)
                                upper_diag_np = np.asarray(upper_diag, dtype=np.float64)
                                max_lower = int(lower_idx_np.shape[1])
                                max_upper = int(upper_idx_np.shape[1])
                                perm_r_full[:block_size] = perm_r_np
                                inv_perm_c_full[:block_size] = inv_perm_c_np
                                lower_idx_full = -np.ones((block_size_max, max_lower), dtype=np.int32)
                                lower_val_full = np.zeros((block_size_max, max_lower), dtype=np.float64)
                                lower_idx_full[:block_size, :] = lower_idx_np
                                lower_val_full[:block_size, :] = lower_val_np
                                upper_idx_full = -np.ones((block_size_max, max_upper), dtype=np.int32)
                                upper_val_full = np.zeros((block_size_max, max_upper), dtype=np.float64)
                                upper_idx_full[:block_size, :] = upper_idx_np
                                upper_val_full[:block_size, :] = upper_val_np
                                upper_diag_full[:block_size] = upper_diag_np
                            elif emit is not None:
                                emit(
                                    1,
                                    "xblock_sparse: missing JAX factors for block "
                                    f"(species={int(s)} x={int(ix)} size={int(block_size)}); using identity",
                                )

                    perm_r_blocks.append(perm_r_full)
                    inv_perm_c_blocks.append(inv_perm_c_full)
                    lower_idx_blocks.append(lower_idx_full)
                    lower_val_blocks.append(lower_val_full)
                    upper_idx_blocks.append(upper_idx_full)
                    upper_val_blocks.append(upper_val_full)
                    upper_diag_blocks.append(upper_diag_full)
                    max_lower_global = max(max_lower_global, int(lower_idx_full.shape[1]))
                    max_upper_global = max(max_upper_global, int(upper_idx_full.shape[1]))

            for i in range(len(lower_idx_blocks)):
                lower_idx_block = lower_idx_blocks[i]
                lower_val_block = lower_val_blocks[i]
                upper_idx_block = upper_idx_blocks[i]
                upper_val_block = upper_val_blocks[i]
                if int(lower_idx_block.shape[1]) < max_lower_global:
                    pad = int(max_lower_global - int(lower_idx_block.shape[1]))
                    lower_idx_block = np.pad(lower_idx_block, ((0, 0), (0, pad)), constant_values=-1)
                    lower_val_block = np.pad(lower_val_block, ((0, 0), (0, pad)), constant_values=0.0)
                if int(upper_idx_block.shape[1]) < max_upper_global:
                    pad = int(max_upper_global - int(upper_idx_block.shape[1]))
                    upper_idx_block = np.pad(upper_idx_block, ((0, 0), (0, pad)), constant_values=-1)
                    upper_val_block = np.pad(upper_val_block, ((0, 0), (0, pad)), constant_values=0.0)
                lower_idx_blocks[i] = lower_idx_block
                lower_val_blocks[i] = lower_val_block
                upper_idx_blocks[i] = upper_idx_block
                upper_val_blocks[i] = upper_val_block

            perm_r_np = np.stack(perm_r_blocks, axis=0).reshape((n_species, n_x, block_size_max))
            inv_perm_c_np = np.stack(inv_perm_c_blocks, axis=0).reshape((n_species, n_x, block_size_max))
            lower_idx_np = np.stack(lower_idx_blocks, axis=0).reshape(
                (n_species, n_x, block_size_max, max_lower_global)
            )
            lower_val_np = np.stack(lower_val_blocks, axis=0).reshape(
                (n_species, n_x, block_size_max, max_lower_global)
            )
            upper_idx_np = np.stack(upper_idx_blocks, axis=0).reshape(
                (n_species, n_x, block_size_max, max_upper_global)
            )
            upper_val_np = np.stack(upper_val_blocks, axis=0).reshape(
                (n_species, n_x, block_size_max, max_upper_global)
            )
            upper_diag_np = np.stack(upper_diag_blocks, axis=0).reshape((n_species, n_x, block_size_max))

            extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
            extra_inv_jnp: jnp.ndarray | None = None
            if extra_size > 0:
                chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
                y_sub = _matvec_submatrix(
                    op,
                    col_idx=extra_idx_np,
                    row_idx=extra_idx_np,
                    total_size=total_size,
                    chunk_cols=chunk_cols,
                )
                ee = np.asarray(y_sub.T, dtype=np.float64)
                ee = ee + np.float64(reg_val) * np.eye(extra_size, dtype=np.float64)
                try:
                    ee_inv = np.linalg.inv(ee)
                except np.linalg.LinAlgError:
                    ee_inv = np.linalg.pinv(ee, rcond=1e-12)
                if not np.all(np.isfinite(ee_inv)):
                    ee_inv = np.linalg.pinv(ee, rcond=1e-12)
                extra_inv_jnp = jnp.asarray(ee_inv, dtype=jnp.float64)

            cached = _RHSMode1SparseXBlockPrecondCache(
                perm_r_sx=jnp.asarray(perm_r_np, dtype=jnp.int32),
                inv_perm_c_sx=jnp.asarray(inv_perm_c_np, dtype=jnp.int32),
                lower_idx_sx=jnp.asarray(lower_idx_np, dtype=jnp.int32),
                lower_val_sx=jnp.asarray(lower_val_np, dtype=jnp.float64),
                upper_idx_sx=jnp.asarray(upper_idx_np, dtype=jnp.int32),
                upper_val_sx=jnp.asarray(upper_val_np, dtype=jnp.float64),
                upper_diag_sx=jnp.asarray(upper_diag_np, dtype=jnp.float64),
                extra_idx_jnp=extra_idx_jnp,
                extra_inv_jnp=extra_inv_jnp,
            )
            _RHSMODE1_SPARSE_XBLOCK_PRECOND_CACHE[cache_key] = cached
        else:
            block_slices: list[tuple[int, int]] = []
            block_factors: list[object | None] = []
            block_diag_inv: list[np.ndarray | None] = []

            def _maybe_skipped_diag_inv(*, species: int, ix: int, block_size: int) -> np.ndarray | None:
                if (not bool(skipped_diag_fallback)) or (not bool(assembled_host_fp)) or block_size <= 0:
                    return None
                try:
                    diag = _rhsmode1_fp_xblock_tz_sparse_diagonal(
                        op=op,
                        species=int(species),
                        ix=int(ix),
                        preconditioner_xi=preconditioner_xi,
                        host_cache=assembled_host_cache,
                    )
                    diag_inv = _safe_inverse_diagonal_np(diag, floor=float(skipped_diag_floor))
                    if diag_inv is not None and int(diag_inv.size) == int(block_size):
                        if emit is not None:
                            emit(
                                1,
                                "xblock_sparse_host: using diagonal fallback for skipped/rejected block "
                                f"(species={int(species)} x={int(ix)} size={int(block_size)})",
                            )
                        return diag_inv
                except Exception as exc:  # noqa: BLE001
                    if emit is not None:
                        emit(
                            1,
                            "xblock_sparse_host: diagonal fallback unavailable for block "
                            f"(species={int(species)} x={int(ix)} size={int(block_size)}) "
                            f"({type(exc).__name__}: {exc})",
                        )
                return None

            for s in range(n_species):
                for ix in range(n_x):
                    n_lx = int(nxi_for_x[ix])
                    block_size = int(n_lx * n_theta * n_zeta)
                    start = int((((s * n_x + ix) * n_l) * n_theta) * n_zeta)
                    if block_size <= 0:
                        continue
                    block_slice = slice(start, start + block_size)
                    if (
                        not build_jax_factors
                        and not _rhs1_xblock_sparse_host_policy.rhs1_xblock_sparse_host_block_factor_allowed(
                            block_size=int(block_size),
                            max_block_size_env_value=host_block_max_env,
                        )
                    ):
                        if emit is not None:
                            emit(
                                1,
                                "xblock_sparse_host: skipping local factor "
                                f"(species={int(s)} x={int(ix)} size={int(block_size)} "
                                "exceeds host block cap; set "
                                "SFINCS_JAX_RHSMODE1_XBLOCK_SPARSE_HOST_BLOCK_MAX=0 "
                                "to force the historical uncapped path)",
                            )
                        block_slices.append((start, block_size))
                        block_factors.append(None)
                        block_diag_inv.append(
                            _maybe_skipped_diag_inv(species=int(s), ix=int(ix), block_size=int(block_size))
                        )
                        continue

                    def _mv_block(v_block: jnp.ndarray, *, _block_slice=block_slice) -> jnp.ndarray:
                        x_full = jnp.zeros((total_size,), dtype=v_block.dtype)
                        x_full = x_full.at[_block_slice].set(v_block)
                        y_full = apply_v3_full_system_operator_cached(op, x_full)
                        return y_full[_block_slice]

                    block_cache_key = (cache_key, int(s), int(ix), int(block_size))
                    local_candidate = _local_factor_candidate(block_size)
                    if local_candidate.lower_fill and emit is not None:
                        emit(
                            1,
                            "xblock_sparse_host: lower-fill local factor "
                            f"(species={int(s)} x={int(ix)} size={int(block_size)} "
                            f"drop_tol={local_candidate.tuning.ilu_drop_tol:.1e} "
                            f"fill={local_candidate.tuning.fill_factor:.1f} "
                            f"row_cap={int(local_candidate.tuning.row_nnz_cap)} "
                            f"reason={local_candidate.selection_reason})",
                        )
                    try:
                        fac_cache = _RHSMODE1_SPARSE_ILU_CACHE.get(block_cache_key)
                        if fac_cache is None or fac_cache.ilu is None:
                            if assembled_host_fp:
                                if emit is not None:
                                    emit(
                                        1,
                                        "xblock_sparse_host: assembling explicit FP x-block "
                                        f"(species={int(s)} x={int(ix)} size={int(block_size)})",
                                    )
                                a_block = _assemble_rhsmode1_fp_xblock_tz_sparse_matrix(
                                    op=op,
                                    species=int(s),
                                    ix=int(ix),
                                    preconditioner_xi=preconditioner_xi,
                                    host_cache=assembled_host_cache,
                                )
                                _factorize_sparse_matrix_csr_host(
                                    a_csr_full=a_block.tocsr(),
                                    cache_key=block_cache_key,
                                    drop_tol=local_candidate.tuning.drop_tol,
                                    drop_rel=local_candidate.tuning.drop_rel,
                                    ilu_drop_tol=local_candidate.tuning.ilu_drop_tol,
                                    fill_factor=local_candidate.tuning.fill_factor,
                                    factorization=local_candidate.factorization,
                                    emit=emit,
                                )
                            else:
                                _build_sparse_ilu_from_matvec(
                                    matvec=_mv_block,
                                    n=int(block_size),
                                    dtype=jnp.float64,
                                    cache_key=block_cache_key,
                                    drop_tol=local_candidate.tuning.drop_tol,
                                    drop_rel=local_candidate.tuning.drop_rel,
                                    ilu_drop_tol=local_candidate.tuning.ilu_drop_tol,
                                    fill_factor=local_candidate.tuning.fill_factor,
                                    build_dense_factors=False,
                                    build_jax_factors=False,
                                    build_ilu=True,
                                    store_dense=False,
                                    factorization=local_candidate.factorization,
                                    row_nnz_cap=int(local_candidate.tuning.row_nnz_cap),
                                    emit=emit,
                                )
                            fac_cache = _RHSMODE1_SPARSE_ILU_CACHE.get(block_cache_key)
                    except Exception as exc:  # noqa: BLE001
                        fac_cache = None
                        if emit is not None:
                            emit(
                                1,
                                "xblock_sparse_host: factorization failed for block "
                                f"(species={int(s)} x={int(ix)} size={int(block_size)}) "
                                f"({type(exc).__name__}: {exc})",
                            )
                    host_factor = None if fac_cache is None else fac_cache.ilu
                    if assembled_host_fp and host_factor is not None:
                        if not _rhsmode1_host_factor_probe_ok(factor=host_factor, block_size=int(block_size)):
                            if emit is not None:
                                emit(
                                    1,
                                    "xblock_sparse_host: rejecting unstable block factor "
                                    f"(species={int(s)} x={int(ix)} size={int(block_size)})",
                            )
                            host_factor = None
                    block_slices.append((start, block_size))
                    block_factors.append(host_factor)
                    block_diag_inv.append(
                        None
                        if host_factor is not None
                        else _maybe_skipped_diag_inv(species=int(s), ix=int(ix), block_size=int(block_size))
                    )

            extra_inv_np: np.ndarray | None = None
            if extra_size > 0:
                chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
                y_sub = _matvec_submatrix(
                    op,
                    col_idx=extra_idx_np,
                    row_idx=extra_idx_np,
                    total_size=total_size,
                    chunk_cols=chunk_cols,
                )
                ee = np.asarray(y_sub.T, dtype=np.float64)
                ee = ee + np.float64(reg_val) * np.eye(extra_size, dtype=np.float64)
                try:
                    extra_inv_np = np.linalg.inv(ee)
                except np.linalg.LinAlgError:
                    extra_inv_np = np.linalg.pinv(ee, rcond=1e-12)
                if not np.all(np.isfinite(extra_inv_np)):
                    extra_inv_np = np.linalg.pinv(ee, rcond=1e-12)

            cached = _RHSMode1SparseXBlockHostPrecondCache(
                block_slices=tuple(block_slices),
                block_factors=tuple(block_factors),
                block_diag_inv=tuple(block_diag_inv),
                extra_idx_np=extra_idx_np,
                extra_inv_np=extra_inv_np,
            )
            _RHSMODE1_SPARSE_XBLOCK_HOST_PRECOND_CACHE[cache_key] = cached

    if build_jax_factors and xblock_jax_factor_format == "csr":
        perm_r_sx = cached.perm_r_sx
        inv_perm_c_sx = cached.inv_perm_c_sx
        lower_indptr = cached.lower_indptr
        lower_indices = cached.lower_indices
        lower_val = cached.lower_val
        upper_indptr = cached.upper_indptr
        upper_indices = cached.upper_indices
        upper_val = cached.upper_val
        upper_diag_sx = cached.upper_diag_sx
        extra_idx_jnp = cached.extra_idx_jnp
        extra_inv_jnp = cached.extra_inv_jnp

        f_size = int(op.f_size)
        n_blocks = int(n_species * n_x)
        block_ids = jnp.arange(n_blocks, dtype=jnp.int32)
        row_stride = jnp.asarray(block_size_max + 1, dtype=jnp.int32)
        if emit is not None and xblock_jax_factor_apply != "exact":
            emit(
                1,
                "xblock_sparse_csr: using approximate compact JAX factor apply "
                f"mode={xblock_jax_factor_apply}",
            )

        def _solve_block_csr(inputs: tuple[jnp.ndarray, jnp.ndarray, jnp.ndarray, jnp.ndarray, jnp.ndarray]) -> jnp.ndarray:
            r, block_id, perm_r, inv_perm_c, upper_diag = inputs
            if xblock_jax_factor_apply == "identity":
                return r
            r_perm = r[perm_r]
            if xblock_jax_factor_apply == "diagonal":
                diag_abs = jnp.abs(upper_diag)
                sign = jnp.where(upper_diag < 0.0, -1.0, 1.0)
                denom = jnp.where(diag_abs > 1.0e-14, upper_diag, sign * 1.0e-14)
                return (r_perm / denom)[inv_perm_c]
            row_base = block_id * row_stride
            if xblock_jax_factor_apply == "lower":
                y = _triangular_solve_lower_csr_rows(
                    indptr=lower_indptr,
                    indices=lower_indices,
                    data=lower_val,
                    b=r_perm,
                    row_base=row_base,
                )
                return y[inv_perm_c]
            if xblock_jax_factor_apply == "upper":
                z = _triangular_solve_upper_csr_rows(
                    indptr=upper_indptr,
                    indices=upper_indices,
                    data=upper_val,
                    upper_diag=upper_diag,
                    b=r_perm,
                    row_base=row_base,
                )
                return z[inv_perm_c]
            y = _triangular_solve_lower_csr_rows(
                indptr=lower_indptr,
                indices=lower_indices,
                data=lower_val,
                b=r_perm,
                row_base=row_base,
            )
            z = _triangular_solve_upper_csr_rows(
                indptr=upper_indptr,
                indices=upper_indices,
                data=upper_val,
                upper_diag=upper_diag,
                b=y,
                row_base=row_base,
            )
            return z[inv_perm_c]

        def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
            r_full = jnp.asarray(r_full, dtype=jnp.float64)
            r_blocks = r_full[:f_size].reshape((n_blocks, block_size_max))
            z_blocks = jax.lax.map(
                _solve_block_csr,
                (
                    r_blocks,
                    block_ids,
                    perm_r_sx.reshape((n_blocks, block_size_max)),
                    inv_perm_c_sx.reshape((n_blocks, block_size_max)),
                    upper_diag_sx.reshape((n_blocks, block_size_max)),
                ),
            )
            z_full = jnp.concatenate([z_blocks.reshape((-1,)), r_full[f_size:]], axis=0)
            if extra_inv_jnp is not None:
                r_extra = r_full[extra_idx_jnp]
                z_extra = extra_inv_jnp @ r_extra
                z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
            return jnp.asarray(z_full, dtype=jnp.float64)
    elif build_jax_factors:
        perm_r_sx = cached.perm_r_sx
        inv_perm_c_sx = cached.inv_perm_c_sx
        lower_idx_sx = cached.lower_idx_sx
        lower_val_sx = cached.lower_val_sx
        upper_idx_sx = cached.upper_idx_sx
        upper_val_sx = cached.upper_val_sx
        upper_diag_sx = cached.upper_diag_sx
        extra_idx_jnp = cached.extra_idx_jnp
        extra_inv_jnp = cached.extra_inv_jnp

        f_size = int(op.f_size)

        def _solve_block(
            r: jnp.ndarray,
            perm_r: jnp.ndarray,
            inv_perm_c: jnp.ndarray,
            lower_idx: jnp.ndarray,
            lower_val: jnp.ndarray,
            upper_idx: jnp.ndarray,
            upper_val: jnp.ndarray,
            upper_diag: jnp.ndarray,
        ) -> jnp.ndarray:
            r_perm = r[perm_r]
            y = _triangular_solve_lower_padded(lower_idx=lower_idx, lower_val=lower_val, b=r_perm)
            z = _triangular_solve_upper_padded(
                upper_idx=upper_idx,
                upper_val=upper_val,
                upper_diag=upper_diag,
                b=y,
            )
            return z[inv_perm_c]

        _solve_over_x = jax.vmap(
            _solve_block,
            in_axes=(0, 0, 0, 0, 0, 0, 0, 0),
            out_axes=0,
        )
        _solve_over_sx = jax.vmap(
            _solve_over_x,
            in_axes=(0, 0, 0, 0, 0, 0, 0, 0),
            out_axes=0,
        )
        if emit is not None and xblock_jax_factor_apply != "exact":
            emit(
                1,
                "xblock_sparse: using approximate JAX factor apply "
                f"mode={xblock_jax_factor_apply}",
            )

        def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
            r_full = jnp.asarray(r_full, dtype=jnp.float64)
            r_f = r_full[:f_size].reshape((n_species, n_x, block_size_max))
            if xblock_jax_factor_apply == "identity":
                z_f = r_f
            elif xblock_jax_factor_apply == "diagonal":
                diag_abs = jnp.abs(upper_diag_sx)
                sign = jnp.where(upper_diag_sx < 0.0, -1.0, 1.0)
                denom = jnp.where(diag_abs > 1.0e-14, upper_diag_sx, sign * 1.0e-14)
                r_perm = jnp.take_along_axis(r_f, perm_r_sx, axis=2)
                z_perm = r_perm / denom
                z_f = jnp.take_along_axis(z_perm, inv_perm_c_sx, axis=2)
            elif xblock_jax_factor_apply == "lower":
                r_perm = jnp.take_along_axis(r_f, perm_r_sx, axis=2)
                y = jax.vmap(
                    jax.vmap(
                        lambda r, lower_idx, lower_val: _triangular_solve_lower_padded(
                            lower_idx=lower_idx,
                            lower_val=lower_val,
                            b=r,
                        ),
                        in_axes=(0, 0, 0),
                        out_axes=0,
                    ),
                    in_axes=(0, 0, 0),
                    out_axes=0,
                )(r_perm, lower_idx_sx, lower_val_sx)
                z_f = jnp.take_along_axis(y, inv_perm_c_sx, axis=2)
            elif xblock_jax_factor_apply == "upper":
                r_perm = jnp.take_along_axis(r_f, perm_r_sx, axis=2)
                z_perm = jax.vmap(
                    jax.vmap(
                        lambda r, upper_idx, upper_val, upper_diag: _triangular_solve_upper_padded(
                            upper_idx=upper_idx,
                            upper_val=upper_val,
                            upper_diag=upper_diag,
                            b=r,
                        ),
                        in_axes=(0, 0, 0, 0),
                        out_axes=0,
                    ),
                    in_axes=(0, 0, 0, 0),
                    out_axes=0,
                )(r_perm, upper_idx_sx, upper_val_sx, upper_diag_sx)
                z_f = jnp.take_along_axis(z_perm, inv_perm_c_sx, axis=2)
            else:
                z_f = _solve_over_sx(
                    r_f,
                    perm_r_sx,
                    inv_perm_c_sx,
                    lower_idx_sx,
                    lower_val_sx,
                    upper_idx_sx,
                    upper_val_sx,
                    upper_diag_sx,
                )
            z_full = jnp.concatenate([z_f.reshape((-1,)), r_full[f_size:]], axis=0)
            if extra_inv_jnp is not None:
                r_extra = r_full[extra_idx_jnp]
                z_extra = extra_inv_jnp @ r_extra
                z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
            return jnp.asarray(z_full, dtype=jnp.float64)
    else:
        def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
            r_np = np.asarray(r_full, dtype=np.float64).reshape((-1,))
            z_np = np.array(r_np, copy=True)
            for (start, block_size), fac, diag_inv in zip(
                cached.block_slices,
                cached.block_factors,
                cached.block_diag_inv,
                strict=True,
            ):
                if block_size <= 0:
                    continue
                sl = slice(int(start), int(start + block_size))
                if fac is not None:
                    z_np[sl] = np.asarray(fac.solve(r_np[sl]), dtype=np.float64)
                elif diag_inv is not None:
                    z_np[sl] = np.asarray(diag_inv, dtype=np.float64) * r_np[sl]
            if cached.extra_inv_np is not None and cached.extra_idx_np.size:
                z_np[cached.extra_idx_np] = cached.extra_inv_np @ r_np[cached.extra_idx_np]
            return jnp.asarray(z_np, dtype=jnp.float64)

    apply_full_safe = _safe_preconditioner(_apply_full)

    if reduce_full is None or expand_reduced is None:
        return apply_full_safe

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full_safe(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_sxblock_tz_sparse_host_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    drop_tol: float,
    drop_rel: float,
    ilu_drop_tol: float,
    fill_factor: float,
    emit: Callable[[int, str], None] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Explicit-only sparse per-L species/x rescue preconditioner for large FP systems."""
    cache_key = (
        *_rhsmode1_precond_cache_key(op, "sxblock_tz_sparse_host"),
        float(drop_tol),
        float(drop_rel),
        float(ilu_drop_tol),
        float(fill_factor),
    )
    cached = _RHSMODE1_SPARSE_SXBLOCK_HOST_PRECOND_CACHE.get(cache_key)
    n_species = int(op.n_species)
    n_x = int(op.n_x)
    n_l = int(op.n_xi)
    n_theta = int(op.n_theta)
    n_zeta = int(op.n_zeta)
    total_size = int(op.total_size)
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    lu_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_SXBLOCK_SPARSE_LU_MAX", "").strip()
    try:
        lu_max = int(lu_max_env) if lu_max_env else 4000
    except ValueError:
        lu_max = 4000
    lu_max = max(0, int(lu_max))

    if cached is None:
        import scipy.sparse as sp  # noqa: PLC0415

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        struct_tol = _sparse_structural_tol()
        block_indices: list[np.ndarray] = []
        block_factors: list[object | None] = []
        for il in range(n_l):
            active_x = np.where(nxi_for_x > il)[0]
            if active_x.size == 0:
                continue
            idx: list[int] = []
            for s in range(n_species):
                for ix in active_x:
                    base = int((((s * n_x + int(ix)) * n_l + il) * n_theta) * n_zeta)
                    for it in range(n_theta):
                        for iz in range(n_zeta):
                            idx.append(base + it * n_zeta + iz)
            rep_idx_np = np.asarray(idx, dtype=np.int32)
            block_cache_key = (cache_key, int(il), int(rep_idx_np.size))
            exact_lu = int(rep_idx_np.size) <= int(lu_max)
            try:
                if emit is not None:
                    emit(
                        1,
                        "sxblock_sparse_host: assembling per-L species/x block "
                        f"(L={int(il)} size={int(rep_idx_np.size)})",
                    )
                chunk_cols = _precond_chunk_cols(total_size, int(rep_idx_np.shape[0]))
                y_sub = _matvec_submatrix(
                    op,
                    col_idx=rep_idx_np,
                    row_idx=rep_idx_np,
                    total_size=total_size,
                    chunk_cols=chunk_cols,
                )
                a_block = np.asarray(y_sub.T, dtype=np.float64)
                if struct_tol > 0.0 and a_block.size:
                    a_block[np.abs(a_block) <= struct_tol] = 0.0
                a_csr = sp.csr_matrix(a_block)
                a_csr.eliminate_zeros()
                _factorize_sparse_matrix_csr_host(
                    a_csr_full=a_csr,
                    cache_key=block_cache_key,
                    drop_tol=drop_tol,
                    drop_rel=drop_rel,
                    ilu_drop_tol=ilu_drop_tol,
                    fill_factor=fill_factor,
                    factorization="lu" if exact_lu else "ilu",
                    emit=emit,
                )
                fac_cache = _RHSMODE1_SPARSE_ILU_CACHE.get(block_cache_key)
            except Exception as exc:  # noqa: BLE001
                fac_cache = None
                if emit is not None:
                    emit(
                        1,
                        "sxblock_sparse_host: factorization failed for block "
                        f"(L={int(il)} size={int(rep_idx_np.size)}) "
                        f"({type(exc).__name__}: {exc})",
                    )
            host_factor = None if fac_cache is None else fac_cache.ilu
            if host_factor is not None and (
                not _rhsmode1_host_factor_probe_ok(factor=host_factor, block_size=int(rep_idx_np.size))
            ):
                if emit is not None:
                    emit(
                        1,
                        "sxblock_sparse_host: rejecting unstable block factor "
                        f"(L={int(il)} size={int(rep_idx_np.size)})",
                    )
                host_factor = None
            block_indices.append(rep_idx_np)
            block_factors.append(host_factor)

        extra_inv_np: np.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + np.float64(reg_val) * np.eye(extra_size, dtype=np.float64)
            try:
                extra_inv_np = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                extra_inv_np = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(extra_inv_np)):
                extra_inv_np = np.linalg.pinv(ee, rcond=1e-12)

        cached = _RHSMode1SparseSXBlockHostPrecondCache(
            block_indices=tuple(block_indices),
            block_factors=tuple(block_factors),
            extra_idx_np=extra_idx_np,
            extra_inv_np=extra_inv_np,
        )
        _RHSMODE1_SPARSE_SXBLOCK_HOST_PRECOND_CACHE[cache_key] = cached

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_np = np.asarray(r_full, dtype=np.float64).reshape((-1,))
        z_np = np.array(r_np, copy=True)
        for idx_np, fac in zip(cached.block_indices, cached.block_factors, strict=True):
            if fac is None or idx_np.size == 0:
                continue
            z_np[idx_np] = np.asarray(fac.solve(r_np[idx_np]), dtype=np.float64)
        if cached.extra_inv_np is not None and cached.extra_idx_np.size:
            z_np[cached.extra_idx_np] = cached.extra_inv_np @ r_np[cached.extra_idx_np]
        return jnp.asarray(z_np, dtype=jnp.float64)

    apply_full_safe = _safe_preconditioner(_apply_full)

    if reduce_full is None or expand_reduced is None:
        return apply_full_safe

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full_safe(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _compute_rhsmode1_sxblock_tz_sparse_host_seed(
    *,
    op: V3FullSystemOperator,
    rhs_reduced: jnp.ndarray,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    drop_tol: float,
    drop_rel: float,
    ilu_drop_tol: float,
    fill_factor: float,
    emit: Callable[[int, str], None] | None = None,
) -> jnp.ndarray:
    """Build an explicit sxblock_tz seed without retaining all per-L factors."""
    import scipy.sparse as sp  # noqa: PLC0415

    rhs_full = expand_reduced(rhs_reduced) if expand_reduced is not None else rhs_reduced
    rhs_full_np = np.asarray(rhs_full, dtype=np.float64).reshape((-1,))
    seed_full_np = np.array(rhs_full_np, copy=True)

    n_species = int(op.n_species)
    n_x = int(op.n_x)
    n_l = int(op.n_xi)
    n_theta = int(op.n_theta)
    n_zeta = int(op.n_zeta)
    total_size = int(op.total_size)
    nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
    lu_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_SXBLOCK_SPARSE_LU_MAX", "").strip()
    chunk_cols_env = os.environ.get("SFINCS_JAX_RHSMODE1_SXBLOCK_CHUNK_COLS", "").strip()
    try:
        lu_max = int(lu_max_env) if lu_max_env else 4000
    except ValueError:
        lu_max = 4000
    lu_max = max(0, int(lu_max))
    try:
        chunk_cols_cap = int(chunk_cols_env) if chunk_cols_env else 32
    except ValueError:
        chunk_cols_cap = 32
    chunk_cols_cap = max(1, int(chunk_cols_cap))
    struct_tol = _sparse_structural_tol()

    for il in range(n_l):
        active_x = np.where(nxi_for_x > il)[0]
        if active_x.size == 0:
            continue
        idx: list[int] = []
        for s in range(n_species):
            for ix in active_x:
                base = int((((s * n_x + int(ix)) * n_l + il) * n_theta) * n_zeta)
                for it in range(n_theta):
                    for iz in range(n_zeta):
                        idx.append(base + it * n_zeta + iz)
        rep_idx_np = np.asarray(idx, dtype=np.int32)
        exact_lu = int(rep_idx_np.size) <= int(lu_max)
        block_cache_key = (
            *_rhsmode1_precond_cache_key(op, "sxblock_tz_sparse_seed"),
            int(il),
            int(rep_idx_np.size),
            float(drop_tol),
            float(drop_rel),
            float(ilu_drop_tol),
            float(fill_factor),
            int(exact_lu),
        )
        try:
            if emit is not None:
                emit(
                    1,
                    "sxblock_sparse_seed: assembling per-L species/x block "
                    f"(L={int(il)} size={int(rep_idx_np.size)})",
                )
            chunk_cols = min(_precond_chunk_cols(total_size, int(rep_idx_np.shape[0])), int(chunk_cols_cap))
            y_sub = _matvec_submatrix(
                op,
                col_idx=rep_idx_np,
                row_idx=rep_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            a_block = np.asarray(y_sub.T, dtype=np.float64)
            if struct_tol > 0.0 and a_block.size:
                a_block[np.abs(a_block) <= struct_tol] = 0.0
            a_csr = sp.csr_matrix(a_block)
            a_csr.eliminate_zeros()
            _factorize_sparse_matrix_csr_host(
                a_csr_full=a_csr,
                cache_key=block_cache_key,
                drop_tol=drop_tol,
                drop_rel=drop_rel,
                ilu_drop_tol=ilu_drop_tol,
                fill_factor=fill_factor,
                factorization="lu" if exact_lu else "ilu",
                emit=emit,
            )
            fac_cache = _RHSMODE1_SPARSE_ILU_CACHE.pop(block_cache_key, None)
            fac = None if fac_cache is None else fac_cache.ilu
            if fac is None:
                continue
            sol = np.asarray(fac.solve(rhs_full_np[rep_idx_np]), dtype=np.float64)
            if np.all(np.isfinite(sol)):
                seed_full_np[rep_idx_np] = sol
        except Exception as exc:  # noqa: BLE001
            if emit is not None:
                emit(
                    1,
                    "sxblock_sparse_seed: block solve failed "
                    f"(L={int(il)} size={int(rep_idx_np.size)}) "
                    f"({type(exc).__name__}: {exc})",
                )

    extra_start = int(op.f_size + op.phi1_size)
    extra_size = int(op.extra_size)
    if extra_size > 0:
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
        y_sub = _matvec_submatrix(
            op,
            col_idx=extra_idx_np,
            row_idx=extra_idx_np,
            total_size=total_size,
            chunk_cols=chunk_cols,
        )
        ee = np.asarray(y_sub.T, dtype=np.float64)
        ee = ee + np.float64(reg_val) * np.eye(extra_size, dtype=np.float64)
        try:
            extra_inv_np = np.linalg.inv(ee)
        except np.linalg.LinAlgError:
            extra_inv_np = np.linalg.pinv(ee, rcond=1e-12)
        if not np.all(np.isfinite(extra_inv_np)):
            extra_inv_np = np.linalg.pinv(ee, rcond=1e-12)
        seed_full_np[extra_idx_np] = extra_inv_np @ rhs_full_np[extra_idx_np]

    seed_full = jnp.asarray(seed_full_np, dtype=jnp.float64)
    return reduce_full(seed_full) if reduce_full is not None else seed_full


def _build_rhsmode1_sxblock_tz_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a RHSMode=1 preconditioner with species/x blocks over (theta,zeta) per L."""
    cache_key = _rhsmode1_precond_cache_key(op, "sxblock_tz")
    cached = _RHSMODE1_PRECOND_IDX_CACHE.get(cache_key)
    if cached is None:
        n_s = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_t = int(op.n_theta)
        n_z = int(op.n_zeta)
        total = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        max_block_size = 0
        for l in range(n_l):
            active_x = np.where(nxi_for_x > l)[0]
            if active_x.size:
                max_block_size = max(max_block_size, int(active_x.size) * n_s * n_t * n_z)
        precond_dtype = _precond_dtype(max_block_size * max_block_size)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        block_inv_list: list[jnp.ndarray] = []
        block_idx_list: list[jnp.ndarray] = []
        for l in range(n_l):
            active_x = np.where(nxi_for_x > l)[0]
            if active_x.size == 0:
                continue
            idx: list[int] = []
            for s in range(n_s):
                for ix in active_x:
                    base = int((((s * n_x + int(ix)) * n_l + l) * n_t) * n_z)
                    for it in range(n_t):
                        for iz in range(n_z):
                            idx.append(base + it * n_z + iz)
            rep_idx = np.asarray(idx, dtype=np.int32)
            chunk_cols = _precond_chunk_cols(total, int(rep_idx.shape[0]))
            y_sub = _matvec_submatrix(
                op,
                col_idx=rep_idx,
                row_idx=rep_idx,
                total_size=total,
                chunk_cols=chunk_cols,
            )
            a = np.asarray(y_sub.T, dtype=np.float64)
            a = a + reg * np.eye(int(rep_idx.shape[0]), dtype=np.float64)
            try:
                inv = np.linalg.inv(a)
            except np.linalg.LinAlgError:
                inv = np.linalg.pinv(a, rcond=1e-12)
            if not np.all(np.isfinite(inv)):
                inv = np.linalg.pinv(a, rcond=1e-12)
            block_inv_list.append(jnp.asarray(inv, dtype=precond_dtype))
            block_idx_list.append(jnp.asarray(rep_idx, dtype=jnp.int32))

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondIdxCache(
            block_inv_list=tuple(block_inv_list),
            block_idx_list=tuple(block_idx_list),
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_IDX_CACHE[cache_key] = cached

    block_inv_list = cached.block_inv_list
    block_idx_list = cached.block_idx_list
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp
    precond_dtype = block_inv_list[0].dtype if block_inv_list else _precond_dtype()

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        z_full = jnp.zeros_like(r_full)
        for inv, idx in zip(block_inv_list, block_idx_list, strict=True):
            r_loc = r_full[idx]
            z_loc = inv @ r_loc
            z_full = z_full.at[idx].set(z_loc, unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_pas_xblock_ilu_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Sparse block-Jacobi ILU preconditioner for PAS-like RHSMode=1 operators.

    This preconditioner targets PAS DKES / PAS collisionless runs that are *dense* in the
    existing (theta,zeta,L) block inverses, making preconditioner build/application very
    expensive.

    We assemble a sparse approximation to the per-(species,x) (L,theta,zeta) block matrix
    using the same stencil-like operator structure used in the matrix-free apply:
    - collisionless streaming+mirror (ΔL=±1, spatial derivatives)
    - ExB drifts (spatial derivatives, diagonal in L)
    - pitch-angle scattering collisions (diagonal in L and in theta/zeta)

    Then we compute an ILU factorization with SciPy (`spilu`), and convert the L/U factors
    to a padded row format so the apply path is pure JAX (triangular solves) and can run
    inside JITted GMRES iterations.

    Notes
    -----
    - The ILU factorization is *not* differentiated through; gradients for solves come from
      the implicit-diff VJP of the linear solve, not backpropagating through GMRES.
    - This is intended for PAS-only (no FP) operators. For FP, the x-coupling makes a
      per-x block ILU far less effective.
    """
    if op.fblock.pas is None or op.fblock.fp is not None:
        # Not applicable: fall back to existing defaults.
        return _build_rhsmode1_pas_hybrid_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )

    try:
        import scipy.sparse as sp  # noqa: PLC0415
        from scipy.sparse.linalg import spilu, splu  # noqa: PLC0415
    except Exception:
        # SciPy missing: fall back to existing defaults.
        return _build_rhsmode1_pas_hybrid_preconditioner(
            op=op, reduce_full=reduce_full, expand_reduced=expand_reduced
        )

    # Detect the DKES-trajectory branch (strong ExB drift). These PAS systems are often
    # much stiffer / less diagonally-dominant than tokamak-like cases, and the default
    # ILU drop settings can be too aggressive, leading to slow or stalled Krylov solves.
    exb_theta = op.fblock.exb_theta
    exb_zeta = op.fblock.exb_zeta
    use_dkes_exb = bool(getattr(exb_theta, "use_dkes_exb_drift", False)) or bool(
        getattr(exb_zeta, "use_dkes_exb_drift", False)
    )

    # ILU parameters (PETSc-like PCILU defaults). Keep these conservative to
    # avoid unstable factors on ill-conditioned blocks. In particular, we cap
    # the stored nnz-per-row for L/U factors so the JAX-side padded-row format
    # does not explode memory usage on hard PAS blocks.
    ilu_drop_tol_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_ILU_DROP_TOL", "").strip()
    ilu_fill_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_ILU_FILL_FACTOR", "").strip()
    row_nnz_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_ILU_ROW_NNZ_MAX", "").strip()
    reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_ILU_REG", "").strip()
    try:
        # For DKES-like PAS cases, default to a stronger (less dropping) ILU since the
        # operator can be poorly conditioned.
        default_drop = 1e-4 if use_dkes_exb else 1e-3
        ilu_drop_tol = float(ilu_drop_tol_env) if ilu_drop_tol_env else default_drop
    except ValueError:
        ilu_drop_tol = 1e-4 if use_dkes_exb else 1e-3
    try:
        default_fill = 10.0 if use_dkes_exb else 5.0
        ilu_fill_factor = float(ilu_fill_env) if ilu_fill_env else default_fill
    except ValueError:
        ilu_fill_factor = 10.0 if use_dkes_exb else 5.0
    try:
        row_nnz_max = int(row_nnz_env) if row_nnz_env else 64
    except ValueError:
        row_nnz_max = 64
    row_nnz_max = max(0, int(row_nnz_max))
    try:
        reg = float(reg_env) if reg_env else 1e-12
    except ValueError:
        reg = 1e-12
    reg = float(max(reg, 0.0))

    # Cache key: include the physics pieces that affect the assembled sparse block.
    # For small per-x blocks, an exact sparse LU can be both robust and faster overall
    # than a weak ILU (fewer Krylov iterations). We only enable this for small blocks
    # to avoid dense factors in the padded-row JAX format.
    lu_max_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_LU_MAX", "").strip()
    try:
        # For DKES-like PAS systems, the sparse blocks can be much less diagonally-dominant.
        # Default to a larger LU cutoff there for robustness. For non-DKES PAS systems,
        # prefer ILU for medium-sized blocks to reduce factorization time and memory.
        default_lu_max = 5000 if use_dkes_exb else 1000
        lu_max = int(lu_max_env) if lu_max_env else default_lu_max
    except ValueError:
        lu_max = 5000 if use_dkes_exb else 1000
    lu_max = max(0, int(lu_max))
    # Row cap for *exact LU* factors. Exact sparse LU can have substantially more fill than
    # ILU; we allow a higher cap for LU factors (to keep the preconditioner strong) but
    # still cap aggressively to avoid allocating dense padded-row arrays.
    lu_full_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_LU_ROW_NNZ_MAX", "").strip()
    try:
        # Default to a lower LU row cap than earlier revisions to reduce peak RSS.
        # If LU is needed for robustness in a particularly stiff DKES case, this can
        # be increased via env var without touching code.
        lu_full_row_nnz_max = int(lu_full_env) if lu_full_env else 256
    except ValueError:
        lu_full_row_nnz_max = 256
    lu_full_row_nnz_max = max(0, int(lu_full_row_nnz_max))

    colless = op.fblock.collisionless
    pas = op.fblock.pas

    cache_key = (
        *_rhsmode1_precond_cache_key(op, "pas_xblock_ilu"),
        float(op.fblock.identity_shift),
        float(pas.nu_n),
        float(pas.krook),
        _hash_array(pas.nu_d_hat),
        _hash_array(colless.ddtheta),
        _hash_array(colless.ddzeta),
        _hash_array(colless.b_hat_sup_theta),
        _hash_array(colless.b_hat_sup_zeta),
        _hash_array(colless.db_hat_dtheta),
        _hash_array(colless.db_hat_dzeta),
        float(ilu_drop_tol),
        float(ilu_fill_factor),
        int(row_nnz_max),
        float(reg),
        int(lu_max),
        int(lu_full_row_nnz_max),
        bool(exb_theta is not None),
        bool(exb_zeta is not None),
        bool(getattr(exb_theta, "use_dkes_exb_drift", False)) if exb_theta is not None else False,
        bool(getattr(exb_zeta, "use_dkes_exb_drift", False)) if exb_zeta is not None else False,
    )
    cached = _RHSMODE1_PRECOND_ILU_CACHE.get(cache_key)
    if cached is None:
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)
        nxi_for_x = np.asarray(colless.n_xi_for_x, dtype=np.int32)

        # Build sparse derivative matrices on the (theta,zeta) grid. (zeta is fastest.)
        ddtheta = np.asarray(colless.ddtheta, dtype=np.float64)
        ddzeta = np.asarray(colless.ddzeta, dtype=np.float64)
        ddtheta_sp = sp.csr_matrix(ddtheta)
        ddzeta_sp = sp.csr_matrix(ddzeta)
        i_theta = sp.eye(n_theta, format="csr", dtype=np.float64)
        i_zeta = sp.eye(n_zeta, format="csr", dtype=np.float64)
        dtheta_tz = sp.kron(ddtheta_sp, i_zeta, format="csr")
        dzeta_tz = sp.kron(i_theta, ddzeta_sp, format="csr")
        n_tz = int(n_theta * n_zeta)
        i_tz = sp.eye(n_tz, format="csr", dtype=np.float64)

        # Precompute ExB drift diagonal-in-L spatial operator (shared across species/x).
        exb_op_tz: sp.csr_matrix | None = None
        if exb_theta is not None:
            exb_theta_np = exb_theta
            alpha = float(np.asarray(exb_theta_np.alpha, dtype=np.float64).reshape(()))
            delta = float(np.asarray(exb_theta_np.delta, dtype=np.float64).reshape(()))
            dphi = float(np.asarray(exb_theta_np.dphi_hat_dpsi_hat, dtype=np.float64).reshape(()))
            if getattr(exb_theta_np, "use_dkes_exb_drift", False):
                denom = float(np.asarray(exb_theta_np.fsab_hat2, dtype=np.float64).reshape(()))
                coef = np.asarray(exb_theta_np.d_hat * exb_theta_np.b_hat_sub_zeta, dtype=np.float64) / denom
            else:
                b2 = np.asarray(exb_theta_np.b_hat, dtype=np.float64) ** 2
                coef = np.asarray(exb_theta_np.d_hat * exb_theta_np.b_hat_sub_zeta, dtype=np.float64) / b2
            factor = alpha * delta * 0.5 * dphi
            coef_flat = (factor * coef).reshape((-1,))
            exb_op_tz = sp.diags(coef_flat, 0, format="csr") @ dtheta_tz
        if exb_zeta is not None:
            exb_zeta_np = exb_zeta
            alpha = float(np.asarray(exb_zeta_np.alpha, dtype=np.float64).reshape(()))
            delta = float(np.asarray(exb_zeta_np.delta, dtype=np.float64).reshape(()))
            dphi = float(np.asarray(exb_zeta_np.dphi_hat_dpsi_hat, dtype=np.float64).reshape(()))
            if getattr(exb_zeta_np, "use_dkes_exb_drift", False):
                denom = float(np.asarray(exb_zeta_np.fsab_hat2, dtype=np.float64).reshape(()))
                coef = np.asarray(exb_zeta_np.d_hat * exb_zeta_np.b_hat_sub_theta, dtype=np.float64) / denom
            else:
                b2 = np.asarray(exb_zeta_np.b_hat, dtype=np.float64) ** 2
                coef = np.asarray(exb_zeta_np.d_hat * exb_zeta_np.b_hat_sub_theta, dtype=np.float64) / b2
            factor = -alpha * delta * 0.5 * dphi
            coef_flat = (factor * coef).reshape((-1,))
            term = sp.diags(coef_flat, 0, format="csr") @ dzeta_tz
            exb_op_tz = term if exb_op_tz is None else (exb_op_tz + term)

        # Geometry pieces for collisionless streaming/mirror.
        b_hat = np.asarray(colless.b_hat, dtype=np.float64)
        v_theta = np.asarray(colless.b_hat_sup_theta, dtype=np.float64) / b_hat
        v_zeta = np.asarray(colless.b_hat_sup_zeta, dtype=np.float64) / b_hat
        mirror_geom = (
            np.asarray(colless.b_hat_sup_theta, dtype=np.float64) * np.asarray(colless.db_hat_dtheta, dtype=np.float64)
            + np.asarray(colless.b_hat_sup_zeta, dtype=np.float64) * np.asarray(colless.db_hat_dzeta, dtype=np.float64)
        )
        mirror_geom = np.asarray(mirror_geom, dtype=np.float64)

        t_hat = np.asarray(op.t_hat, dtype=np.float64).reshape((n_species,))
        m_hat = np.asarray(op.m_hat, dtype=np.float64).reshape((n_species,))
        x_arr = np.asarray(colless.x, dtype=np.float64).reshape((n_x,))
        pas_coef = np.asarray(pas.coef, dtype=np.float64)  # (S,X,Lmax)
        identity_shift = float(np.asarray(op.fblock.identity_shift, dtype=np.float64).reshape(()))

        # Precompute per-species spatial operators.
        stream_op_by_s: list[sp.csr_matrix] = []
        mirror_diag_by_s: list[sp.csr_matrix] = []
        sqrt_t_over_m = np.sqrt(t_hat / m_hat)  # (S,)
        for s in range(n_species):
            v_theta_s_flat = (sqrt_t_over_m[s] * v_theta).reshape((-1,))
            v_zeta_s_flat = (sqrt_t_over_m[s] * v_zeta).reshape((-1,))
            stream = sp.diags(v_theta_s_flat, 0, format="csr") @ dtheta_tz
            stream = stream + (sp.diags(v_zeta_s_flat, 0, format="csr") @ dzeta_tz)
            stream_op_by_s.append(stream)

            mirror_factor_flat = (-sqrt_t_over_m[s] * mirror_geom / (2.0 * (b_hat**2))).reshape((-1,))
            mirror_diag_by_s.append(sp.diags(mirror_factor_flat, 0, format="csr"))

        block_size_max = int(n_l * n_tz)
        # Store one block per (species,x), matching F-block layout.
        n_blocks = int(n_species) * int(n_x)
        inv_perm_r_blocks: list[np.ndarray | None] = [None] * n_blocks
        perm_c_blocks: list[np.ndarray | None] = [None] * n_blocks
        lower_idx_blocks: list[np.ndarray | None] = [None] * n_blocks
        lower_val_blocks: list[np.ndarray | None] = [None] * n_blocks
        upper_idx_blocks: list[np.ndarray | None] = [None] * n_blocks
        upper_val_blocks: list[np.ndarray | None] = [None] * n_blocks
        upper_diag_blocks: list[np.ndarray | None] = [None] * n_blocks
        max_lower_global = 0
        max_upper_global = 0

        def _factor_one(args: tuple[int, int]) -> tuple[int, np.ndarray, np.ndarray, np.ndarray, np.ndarray, np.ndarray, np.ndarray, np.ndarray]:
            s, ix = args
            stream_tz = stream_op_by_s[s]
            mirror_diag = mirror_diag_by_s[s]

            n_lx = int(nxi_for_x[ix])
            active_n = int(n_lx * n_tz)

            # Default: identity for the whole block (used when active_n==0 or ILU fails).
            perm_r_full = np.arange(block_size_max, dtype=np.int32)
            perm_c_full = np.arange(block_size_max, dtype=np.int32)
            inv_perm_r_full = perm_r_full.copy()
            lower_idx_full = np.zeros((block_size_max, 0), dtype=np.int32)
            lower_val_full = np.zeros((block_size_max, 0), dtype=np.float64)
            upper_idx_full = np.zeros((block_size_max, 0), dtype=np.int32)
            upper_val_full = np.zeros((block_size_max, 0), dtype=np.float64)
            upper_diag_full = np.ones((block_size_max,), dtype=np.float64)

            if active_n > 0:
                # L-coupling coefficients for this x.
                l = np.arange(n_lx, dtype=np.float64)
                coef_plus = (l + 1.0) / (2.0 * l + 3.0)
                coef_minus = np.where(l > 0, l / (2.0 * l - 1.0), 0.0)
                coef_m_plus = (l + 1.0) * (l + 2.0) / (2.0 * l + 3.0)
                coef_m_minus = np.where(l > 1, -l * (l - 1.0) / (2.0 * l - 1.0), 0.0)
                coef_plus *= x_arr[ix]
                coef_minus *= x_arr[ix]
                coef_m_plus *= x_arr[ix]
                coef_m_minus *= x_arr[ix]

                # Assemble sparse block matrix for the active L-modes.
                #
                # Previous implementations used a Python nested list + `sp.bmat`, which
                # can be surprisingly expensive. The structure here is block-tridiagonal
                # in L, so build it with Kronecker products.
                diag_vals = identity_shift + np.asarray(pas_coef[s, ix, :n_lx], dtype=np.float64) + float(reg)
                a = sp.kron(sp.diags(diag_vals, 0, format="csr"), i_tz, format="csc")
                if exb_op_tz is not None:
                    a = a + sp.kron(sp.eye(n_lx, format="csr", dtype=np.float64), exb_op_tz, format="csc")
                if n_lx > 1:
                    c_stream = sp.diags(
                        [coef_minus[1:], coef_plus[:-1]],
                        offsets=[-1, 1],
                        shape=(n_lx, n_lx),
                        format="csr",
                        dtype=np.float64,
                    )
                    c_mirror = sp.diags(
                        [coef_m_minus[1:], coef_m_plus[:-1]],
                        offsets=[-1, 1],
                        shape=(n_lx, n_lx),
                        format="csr",
                        dtype=np.float64,
                    )
                    a = a + sp.kron(c_stream, stream_tz, format="csc") + sp.kron(c_mirror, mirror_diag, format="csc")
                a = a.tocsc()

                # Prefer ILU for most PAS blocks to avoid SuperLU exact-LU peak allocations
                # and the resulting resident-set spikes. Fall back to exact LU only if ILU
                # fails to factor (e.g. due to numerical issues) and the block is small enough.
                fac = None
                used_lu = False
                try:
                    # ILU (PETSc PCILU analogue).
                    fac = spilu(
                        a,
                        drop_tol=ilu_drop_tol,
                        fill_factor=ilu_fill_factor,
                        permc_spec="COLAMD",
                    )
                except Exception:  # noqa: BLE001
                    fac = None
                if fac is None and lu_max > 0 and int(active_n) <= int(lu_max):
                    # Exact sparse LU (PETSc PCLU analogue) fallback for robustness.
                    try:
                        fac = splu(a, permc_spec="COLAMD")
                        used_lu = True
                    except Exception:  # noqa: BLE001
                        fac = None

                if fac is not None:
                    perm_r = np.asarray(fac.perm_r, dtype=np.int32)
                    perm_c = np.asarray(fac.perm_c, dtype=np.int32)

                    l_csr = fac.L.tocsr()
                    u_csr = fac.U.tocsr()
                    n = int(active_n)
                    # Truncating exact LU factors can severely degrade preconditioner quality.
                    # For LU factors, allow more fill than the ILU cap, but still cap to
                    # avoid dense padded-row allocations.
                    row_nnz_eff = int(row_nnz_max)
                    if used_lu and lu_full_row_nnz_max > 0:
                        row_nnz_eff = max(int(row_nnz_eff), min(int(n), int(lu_full_row_nnz_max)))

                    # Strict lower-triangular part (unit diagonal assumed).
                    lower_cols: list[np.ndarray] = []
                    lower_vals: list[np.ndarray] = []
                    max_lower = 0
                    for i in range(n):
                        rs = int(l_csr.indptr[i])
                        re = int(l_csr.indptr[i + 1])
                        cols = l_csr.indices[rs:re]
                        vals = l_csr.data[rs:re]
                        mask = cols < i
                        cols = cols[mask].astype(np.int32, copy=False)
                        vals = vals[mask].astype(np.float64, copy=False)
                        if row_nnz_eff > 0 and int(cols.size) > row_nnz_eff:
                            sel = np.argpartition(np.abs(vals), -row_nnz_eff)[-row_nnz_eff:]
                            cols = cols[sel]
                            vals = vals[sel]
                        if cols.size:
                            order = np.argsort(cols)
                            cols = cols[order]
                            vals = vals[order]
                        lower_cols.append(cols)
                        lower_vals.append(vals)
                        max_lower = max(max_lower, int(cols.size))
                    lower_idx = -np.ones((n, max_lower), dtype=np.int32)
                    lower_val = np.zeros((n, max_lower), dtype=np.float64)
                    for i in range(n):
                        k = int(lower_cols[i].size)
                        if k:
                            lower_idx[i, :k] = lower_cols[i]
                            lower_val[i, :k] = lower_vals[i]

                    # Strict upper + diagonal.
                    upper_cols: list[np.ndarray] = []
                    upper_vals: list[np.ndarray] = []
                    upper_diag = np.ones((n,), dtype=np.float64)
                    max_upper = 0
                    for i in range(n):
                        rs = int(u_csr.indptr[i])
                        re = int(u_csr.indptr[i + 1])
                        cols = u_csr.indices[rs:re]
                        vals = u_csr.data[rs:re]
                        diag_mask = cols == i
                        if np.any(diag_mask):
                            upper_diag[i] = float(vals[diag_mask][0])
                        mask = cols > i
                        cols_u = cols[mask].astype(np.int32, copy=False)
                        vals_u = vals[mask].astype(np.float64, copy=False)
                        if row_nnz_eff > 0 and int(cols_u.size) > row_nnz_eff:
                            sel = np.argpartition(np.abs(vals_u), -row_nnz_eff)[-row_nnz_eff:]
                            cols_u = cols_u[sel]
                            vals_u = vals_u[sel]
                        if cols_u.size:
                            order = np.argsort(cols_u)
                            cols_u = cols_u[order]
                            vals_u = vals_u[order]
                        upper_cols.append(cols_u)
                        upper_vals.append(vals_u)
                        max_upper = max(max_upper, int(cols_u.size))
                    upper_idx = -np.ones((n, max_upper), dtype=np.int32)
                    upper_val = np.zeros((n, max_upper), dtype=np.float64)
                    for i in range(n):
                        k = int(upper_cols[i].size)
                        if k:
                            upper_idx[i, :k] = upper_cols[i]
                            upper_val[i, :k] = upper_vals[i]

                    bad = ~np.isfinite(upper_diag) | (upper_diag == 0.0)
                    if np.any(bad):
                        upper_diag[bad] = 1.0

                    # Pad to the full x-block size by appending identity rows/cols.
                    perm_r_full[:n] = perm_r
                    perm_c_full[:n] = perm_c
                    inv_perm_r_full = _inverse_permutation(perm_r_full)

                    lower_idx_full = -np.ones((block_size_max, max_lower), dtype=np.int32)
                    lower_val_full = np.zeros((block_size_max, max_lower), dtype=np.float64)
                    lower_idx_full[:n, :] = lower_idx
                    lower_val_full[:n, :] = lower_val

                    upper_idx_full = -np.ones((block_size_max, max_upper), dtype=np.int32)
                    upper_val_full = np.zeros((block_size_max, max_upper), dtype=np.float64)
                    upper_idx_full[:n, :] = upper_idx
                    upper_val_full[:n, :] = upper_val

                    upper_diag_full = np.ones((block_size_max,), dtype=np.float64)
                    upper_diag_full[:n] = upper_diag

            block_idx = int(s) * int(n_x) + int(ix)
            return (
                block_idx,
                inv_perm_r_full,
                perm_c_full,
                lower_idx_full,
                lower_val_full,
                upper_idx_full,
                upper_val_full,
                upper_diag_full,
            )

        args_list = [(s, ix) for s in range(n_species) for ix in range(n_x)]
        threads_env = os.environ.get("SFINCS_JAX_RHSMODE1_PAS_ILU_THREADS", "").strip()
        try:
            threads_req = int(threads_env) if threads_env else 0
        except ValueError:
            threads_req = 0
        if threads_req > 0:
            n_workers = min(int(threads_req), int(n_blocks))
        else:
            # Auto: ILU build is often the dominant cost in PAS DKES cases. Parallelize across
            # independent (species,x) blocks, but cap workers to avoid oversubscribing CPU.
            n_cpu = os.cpu_count() or 1
            n_workers = min(int(n_blocks), max(1, int(n_cpu)), 8)

        if n_workers > 1 and n_blocks > 1:
            from concurrent.futures import ThreadPoolExecutor  # noqa: PLC0415

            with ThreadPoolExecutor(max_workers=int(n_workers)) as ex:
                for (
                    block_idx,
                    inv_perm_r_full,
                    perm_c_full,
                    lower_idx_full,
                    lower_val_full,
                    upper_idx_full,
                    upper_val_full,
                    upper_diag_full,
                ) in ex.map(_factor_one, args_list):
                    inv_perm_r_blocks[block_idx] = inv_perm_r_full
                    perm_c_blocks[block_idx] = perm_c_full
                    lower_idx_blocks[block_idx] = lower_idx_full
                    lower_val_blocks[block_idx] = lower_val_full
                    upper_idx_blocks[block_idx] = upper_idx_full
                    upper_val_blocks[block_idx] = upper_val_full
                    upper_diag_blocks[block_idx] = upper_diag_full
                    max_lower_global = max(max_lower_global, int(lower_idx_full.shape[1]))
                    max_upper_global = max(max_upper_global, int(upper_idx_full.shape[1]))
        else:
            for out in map(_factor_one, args_list):
                (
                    block_idx,
                    inv_perm_r_full,
                    perm_c_full,
                    lower_idx_full,
                    lower_val_full,
                    upper_idx_full,
                    upper_val_full,
                    upper_diag_full,
                ) = out
                inv_perm_r_blocks[block_idx] = inv_perm_r_full
                perm_c_blocks[block_idx] = perm_c_full
                lower_idx_blocks[block_idx] = lower_idx_full
                lower_val_blocks[block_idx] = lower_val_full
                upper_idx_blocks[block_idx] = upper_idx_full
                upper_val_blocks[block_idx] = upper_val_full
                upper_diag_blocks[block_idx] = upper_diag_full
                max_lower_global = max(max_lower_global, int(lower_idx_full.shape[1]))
                max_upper_global = max(max_upper_global, int(upper_idx_full.shape[1]))

        assert all(v is not None for v in inv_perm_r_blocks)
        assert all(v is not None for v in perm_c_blocks)
        assert all(v is not None for v in lower_idx_blocks)
        assert all(v is not None for v in lower_val_blocks)
        assert all(v is not None for v in upper_idx_blocks)
        assert all(v is not None for v in upper_val_blocks)
        assert all(v is not None for v in upper_diag_blocks)

        # Finalize uniform (Klower,Kupper) padding.
        for i in range(len(lower_idx_blocks)):
            lower_idx_block = lower_idx_blocks[i]
            lower_val_block = lower_val_blocks[i]
            upper_idx_block = upper_idx_blocks[i]
            upper_val_block = upper_val_blocks[i]
            assert lower_idx_block is not None
            assert lower_val_block is not None
            assert upper_idx_block is not None
            assert upper_val_block is not None

            if int(lower_idx_block.shape[1]) < max_lower_global:
                pad = int(max_lower_global - int(lower_idx_block.shape[1]))
                lower_idx_block = np.pad(lower_idx_block, ((0, 0), (0, pad)), constant_values=-1)
                lower_val_block = np.pad(lower_val_block, ((0, 0), (0, pad)), constant_values=0.0)
            if int(upper_idx_block.shape[1]) < max_upper_global:
                pad = int(max_upper_global - int(upper_idx_block.shape[1]))
                upper_idx_block = np.pad(upper_idx_block, ((0, 0), (0, pad)), constant_values=-1)
                upper_val_block = np.pad(upper_val_block, ((0, 0), (0, pad)), constant_values=0.0)

            lower_idx_blocks[i] = lower_idx_block
            lower_val_blocks[i] = lower_val_block
            upper_idx_blocks[i] = upper_idx_block
            upper_val_blocks[i] = upper_val_block

        inv_perm_r_np = np.stack(inv_perm_r_blocks, axis=0).reshape((n_species, n_x, block_size_max))  # type: ignore[arg-type]
        perm_c_np = np.stack(perm_c_blocks, axis=0).reshape((n_species, n_x, block_size_max))  # type: ignore[arg-type]
        lower_idx_np = np.stack(lower_idx_blocks, axis=0).reshape(  # type: ignore[arg-type]
            (n_species, n_x, block_size_max, max_lower_global)
        )
        lower_val_np = np.stack(lower_val_blocks, axis=0).reshape(  # type: ignore[arg-type]
            (n_species, n_x, block_size_max, max_lower_global)
        )
        upper_idx_np = np.stack(upper_idx_blocks, axis=0).reshape(  # type: ignore[arg-type]
            (n_species, n_x, block_size_max, max_upper_global)
        )
        upper_val_np = np.stack(upper_val_blocks, axis=0).reshape(  # type: ignore[arg-type]
            (n_species, n_x, block_size_max, max_upper_global)
        )
        upper_diag_np = np.stack(upper_diag_blocks, axis=0).reshape((n_species, n_x, block_size_max))  # type: ignore[arg-type]

        # Extra (constraint) block: keep the existing dense inverse on the small extra subsystem.
        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + float(reg) * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=jnp.float64)

        cached = _RHSMode1ILUBlockPrecondCache(
            inv_perm_r_sx=jnp.asarray(inv_perm_r_np, dtype=jnp.int32),
            perm_c_sx=jnp.asarray(perm_c_np, dtype=jnp.int32),
            lower_idx_sx=jnp.asarray(lower_idx_np, dtype=jnp.int32),
            lower_val_sx=jnp.asarray(lower_val_np, dtype=jnp.float64),
            upper_idx_sx=jnp.asarray(upper_idx_np, dtype=jnp.int32),
            upper_val_sx=jnp.asarray(upper_val_np, dtype=jnp.float64),
            upper_diag_sx=jnp.asarray(upper_diag_np, dtype=jnp.float64),
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_ILU_CACHE[cache_key] = cached

    inv_perm_r_sx = cached.inv_perm_r_sx
    perm_c_sx = cached.perm_c_sx
    lower_idx_sx = cached.lower_idx_sx
    lower_val_sx = cached.lower_val_sx
    upper_idx_sx = cached.upper_idx_sx
    upper_val_sx = cached.upper_val_sx
    upper_diag_sx = cached.upper_diag_sx
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp

    f_size = int(op.f_size)
    n_species = int(op.n_species)
    n_x = int(op.n_x)
    block_size_max = int(inv_perm_r_sx.shape[-1])

    def _solve_block(
        r: jnp.ndarray,
        inv_perm_r: jnp.ndarray,
        perm_c: jnp.ndarray,
        lower_idx: jnp.ndarray,
        lower_val: jnp.ndarray,
        upper_idx: jnp.ndarray,
        upper_val: jnp.ndarray,
        upper_diag: jnp.ndarray,
    ) -> jnp.ndarray:
        r_perm = r[inv_perm_r]
        y = _triangular_solve_lower_padded(lower_idx=lower_idx, lower_val=lower_val, b=r_perm)
        z = _triangular_solve_upper_padded(
            upper_idx=upper_idx, upper_val=upper_val, upper_diag=upper_diag, b=y
        )
        return z[perm_c]

    _solve_over_x = jax.vmap(
        _solve_block,
        in_axes=(0, 0, 0, 0, 0, 0, 0, 0),
        out_axes=0,
    )
    _solve_over_sx = jax.vmap(
        _solve_over_x,
        in_axes=(0, 0, 0, 0, 0, 0, 0, 0),
        out_axes=0,
    )

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=jnp.float64)
        r_f = r_full[:f_size].reshape((n_species, n_x, block_size_max))
        z_f = _solve_over_sx(
            r_f,
            inv_perm_r_sx,
            perm_c_sx,
            lower_idx_sx,
            lower_val_sx,
            upper_idx_sx,
            upper_val_sx,
            upper_diag_sx,
        )
        z_full = jnp.concatenate([z_f.reshape((-1,)), r_full[f_size:]], axis=0)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    apply_full_safe = _safe_preconditioner(_apply_full)
    # Expose ILU factor data for higher-level preconditioners (e.g. Schur) that can
    # exploit the per-(species,x) block structure without repeatedly applying the
    # full block-Jacobi operator during preconditioner setup.
    try:  # pragma: no cover - best-effort metadata for performance
        setattr(
            apply_full_safe,
            "_sfincs_pas_ilu_factors",
            (
                inv_perm_r_sx,
                perm_c_sx,
                lower_idx_sx,
                lower_val_sx,
                upper_idx_sx,
                upper_val_sx,
                upper_diag_sx,
            ),
        )
        setattr(apply_full_safe, "_sfincs_pas_ilu_block_size_max", int(block_size_max))
    except Exception:
        pass

    if reduce_full is None or expand_reduced is None:
        return apply_full_safe

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full_safe(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_zeta_line_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a stronger RHSMode=1 preconditioner using zeta-line blocks.

    For each species and each theta plane, solve a representative block that couples
    all zeta points for all local (x,L) unknowns at that theta. This approximates the
    dominant derivative couplings along zeta while ignoring theta derivatives.
    """
    cache_key = _rhsmode1_precond_cache_key(op, "zeta_line")
    precond_dtype = _precond_dtype()
    cached = _RHSMODE1_PRECOND_CACHE.get(cache_key)
    if cached is None:
        op_pc = _build_rhsmode1_preconditioner_operator_zeta_line(op)
        n_species = int(op.n_species)
        n_x = int(op.n_x)
        n_l = int(op.n_xi)
        n_theta = int(op.n_theta)
        n_zeta = int(op.n_zeta)
        total_size = int(op.total_size)

        nxi_for_x = np.asarray(op.fblock.collisionless.n_xi_for_x, dtype=np.int32)
        local_per_species = int(np.sum(nxi_for_x))
        line_size = int(n_zeta * local_per_species)

        reg_env = os.environ.get("SFINCS_JAX_RHSMODE1_PRECOND_REG", "").strip()
        reg_val = float(reg_env) if reg_env else 1e-10
        reg = np.float64(reg_val)

        # Build per-(species,theta) gather map for all zeta points and local (x,L) indices.
        idx_map = np.zeros((n_species, n_theta, line_size), dtype=np.int32)
        for s in range(n_species):
            for it in range(n_theta):
                k = 0
                for iz in range(n_zeta):
                    for ix in range(n_x):
                        max_l = int(nxi_for_x[ix])
                        for il in range(max_l):
                            idx_map[s, it, k] = int(
                                ((((s * n_x + ix) * n_l + il) * n_theta + it) * n_zeta + iz)
                            )
                            k += 1

        idx_map_jnp = jnp.asarray(idx_map, dtype=jnp.int32)
        flat_idx_jnp = idx_map_jnp.reshape((-1,))

        # Invert a zeta-line block for each theta plane.
        block_inv = np.zeros((n_species, n_theta, line_size, line_size), dtype=np.float64)
        for s in range(n_species):
            for it in range(n_theta):
                rep_idx = np.asarray(idx_map[s, it, :], dtype=np.int32)
                chunk_cols = _precond_chunk_cols(total_size, int(rep_idx.shape[0]))
                y_sub = _matvec_submatrix(
                    op_pc,
                    col_idx=rep_idx,
                    row_idx=rep_idx,
                    total_size=total_size,
                    chunk_cols=chunk_cols,
                )
                a = np.asarray(y_sub.T, dtype=np.float64)  # (line_size, line_size)
                a = a + reg * np.eye(line_size, dtype=np.float64)
                try:
                    inv = np.linalg.inv(a)
                except np.linalg.LinAlgError:
                    inv = np.linalg.pinv(a, rcond=1e-12)
                if not np.all(np.isfinite(inv)):
                    inv = np.linalg.pinv(a, rcond=1e-12)
                block_inv[s, it, :, :] = inv
        block_inv_jnp = jnp.asarray(block_inv, dtype=precond_dtype)

        extra_start = int(op.f_size + op.phi1_size)
        extra_size = int(op.extra_size)
        extra_idx_np = np.arange(extra_start, extra_start + extra_size, dtype=np.int32)
        extra_idx_jnp = jnp.asarray(extra_idx_np, dtype=jnp.int32)
        extra_inv_jnp: jnp.ndarray | None = None
        if extra_size > 0:
            chunk_cols = _precond_chunk_cols(total_size, int(extra_idx_np.shape[0]))
            y_sub = _matvec_submatrix(
                op_pc,
                col_idx=extra_idx_np,
                row_idx=extra_idx_np,
                total_size=total_size,
                chunk_cols=chunk_cols,
            )
            ee = np.asarray(y_sub.T, dtype=np.float64)
            ee = ee + reg * np.eye(extra_size, dtype=np.float64)
            try:
                ee_inv = np.linalg.inv(ee)
            except np.linalg.LinAlgError:
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            if not np.all(np.isfinite(ee_inv)):
                ee_inv = np.linalg.pinv(ee, rcond=1e-12)
            extra_inv_jnp = jnp.asarray(ee_inv, dtype=precond_dtype)

        cached = _RHSMode1PrecondCache(
            idx_map_jnp=idx_map_jnp,
            flat_idx_jnp=flat_idx_jnp,
            block_inv_jnp=block_inv_jnp,
            extra_idx_jnp=extra_idx_jnp,
            extra_inv_jnp=extra_inv_jnp,
        )
        _RHSMODE1_PRECOND_CACHE[cache_key] = cached

    n_species = int(op.n_species)
    n_theta = int(op.n_theta)
    line_size = int(cached.block_inv_jnp.shape[-1])
    flat_idx_jnp = cached.flat_idx_jnp
    block_inv_jnp = cached.block_inv_jnp
    extra_idx_jnp = cached.extra_idx_jnp
    extra_inv_jnp = cached.extra_inv_jnp

    def _apply_full(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=precond_dtype)
        r_loc = r_full[flat_idx_jnp].reshape((n_species, n_theta, line_size))
        z_loc = jnp.einsum("stab,stb->sta", block_inv_jnp, r_loc)
        z_full = jnp.zeros_like(r_full)
        z_full = z_full.at[flat_idx_jnp].set(z_loc.reshape((-1,)), unique_indices=True)
        if extra_inv_jnp is not None:
            r_extra = r_full[extra_idx_jnp]
            z_extra = extra_inv_jnp @ r_extra
            z_full = z_full.at[extra_idx_jnp].set(z_extra, unique_indices=True)
        return jnp.asarray(z_full, dtype=jnp.float64)

    if reduce_full is None or expand_reduced is None:
        return _apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = _apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    return _apply_reduced


def _build_rhsmode1_structured_fblock_jacobi_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build an opt-in block-Jacobi preconditioner from the structured f-block.

    This is a default-off integration path for the JAX-native block-COO
    assembly. It only uses the structured operator when all f-block terms are
    covered; otherwise selection fails before Krylov starts.
    """

    phi1_base = op.phi1_hat_base if getattr(op.fblock, "fp_phi1", None) is not None else None
    selection = select_structured_rhs1_fblock_operator(op.fblock, phi1_hat_base=phi1_base)
    if not bool(selection.selected):
        raise NotImplementedError(f"structured f-block preconditioner unavailable: {selection.reason}")

    regularization = _rhs1_float_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_JACOBI_REG",
        default=1.0e-10,
        minimum=0.0,
    )
    damping = _rhs1_float_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_JACOBI_DAMPING",
        default=1.0,
        minimum=0.0,
    )
    factor = selection.assembly.operator.block_jacobi_factor(
        regularization=float(regularization),
        damping=float(damping),
    )
    metadata = selection.to_dict()
    metadata["factor"] = factor.to_dict()
    metadata["regularization"] = float(regularization)
    metadata["damping"] = float(damping)

    f_size = int(op.f_size)

    def _apply_full_unchecked(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=jnp.float64)
        z_f = factor.apply(r_full[:f_size])
        return jnp.concatenate([z_f, r_full[f_size:]], axis=0)

    apply_full = _safe_preconditioner(_apply_full_unchecked)
    setattr(apply_full, "_sfincs_jax_structured_fblock_metadata", metadata)

    if reduce_full is None or expand_reduced is None:
        return apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    setattr(_apply_reduced, "_sfincs_jax_structured_fblock_metadata", metadata)
    return _apply_reduced


def _build_rhsmode1_structured_fblock_angular_jacobi_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build an opt-in angular-line preconditioner from the structured f-block.

    Blocks are grouped over theta for each fixed ``(species, x, L)`` while each
    scalar block already contains all zeta couplings.  This captures the full
    local angular surface coupling without dense probing or host sparse assembly.
    """

    phi1_base = op.phi1_hat_base if getattr(op.fblock, "fp_phi1", None) is not None else None
    selection = select_structured_rhs1_fblock_operator(op.fblock, phi1_hat_base=phi1_base)
    if not bool(selection.selected):
        raise NotImplementedError(f"structured f-block angular preconditioner unavailable: {selection.reason}")

    regularization = _rhs1_float_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_ANGULAR_JACOBI_REG",
        default=1.0e-10,
        minimum=0.0,
    )
    damping = _rhs1_float_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_ANGULAR_JACOBI_DAMPING",
        default=1.0,
        minimum=0.0,
    )
    factor = selection.assembly.operator.line_jacobi_factor(
        blocks_per_line=int(op.n_theta),
        regularization=float(regularization),
        damping=float(damping),
    )
    metadata = selection.to_dict()
    metadata["factor"] = factor.to_dict()
    metadata["regularization"] = float(regularization)
    metadata["damping"] = float(damping)
    metadata["line_kind"] = "fixed_species_x_l_angular"
    metadata["blocks_per_line"] = int(op.n_theta)

    f_size = int(op.f_size)

    def _apply_full_unchecked(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=jnp.float64)
        z_f = factor.apply(r_full[:f_size])
        return jnp.concatenate([z_f, r_full[f_size:]], axis=0)

    apply_full = _safe_preconditioner(_apply_full_unchecked)
    setattr(apply_full, "_sfincs_jax_structured_fblock_metadata", metadata)

    if reduce_full is None or expand_reduced is None:
        return apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    setattr(_apply_reduced, "_sfincs_jax_structured_fblock_metadata", metadata)
    return _apply_reduced


def _build_rhsmode1_structured_fblock_xi_angular_jacobi_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a guarded fixed-``(species,x)`` velocity-angular preconditioner.

    The grouped block contains all pitch/Legendre and angular degrees of
    freedom for one species and one radial grid point.  This is stronger than
    point or angular-line Jacobi for PAS/collisionless coupling, but it is
    explicitly guarded because the grouped block scales as
    ``Nxi * Ntheta * Nzeta``.
    """

    blocks_per_line = int(op.n_xi) * int(op.n_theta)
    scalar_block_size = blocks_per_line * int(op.n_zeta)
    max_block_size = _rhs1_int_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_XI_ANGULAR_MAX_BLOCK_SIZE",
        default=5000,
        minimum=1,
    )
    if int(scalar_block_size) > int(max_block_size):
        raise MemoryError(
            "structured f-block xi-angular preconditioner block too large: "
            f"{int(scalar_block_size)} > {int(max_block_size)}; raise "
            "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_XI_ANGULAR_MAX_BLOCK_SIZE to override"
        )

    phi1_base = op.phi1_hat_base if getattr(op.fblock, "fp_phi1", None) is not None else None
    selection = select_structured_rhs1_fblock_operator(op.fblock, phi1_hat_base=phi1_base)
    if not bool(selection.selected):
        raise NotImplementedError(f"structured f-block xi-angular preconditioner unavailable: {selection.reason}")

    regularization = _rhs1_float_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_XI_ANGULAR_JACOBI_REG",
        default=1.0e-10,
        minimum=0.0,
    )
    damping = _rhs1_float_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_XI_ANGULAR_JACOBI_DAMPING",
        default=1.0,
        minimum=0.0,
    )
    factor = selection.assembly.operator.line_jacobi_factor(
        blocks_per_line=blocks_per_line,
        regularization=float(regularization),
        damping=float(damping),
    )
    metadata = selection.to_dict()
    metadata["factor"] = factor.to_dict()
    metadata["regularization"] = float(regularization)
    metadata["damping"] = float(damping)
    metadata["line_kind"] = "fixed_species_x_velocity_angular"
    metadata["blocks_per_line"] = int(blocks_per_line)
    metadata["scalar_block_size"] = int(scalar_block_size)
    metadata["max_block_size"] = int(max_block_size)

    f_size = int(op.f_size)

    def _apply_full_unchecked(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=jnp.float64)
        z_f = factor.apply(r_full[:f_size])
        return jnp.concatenate([z_f, r_full[f_size:]], axis=0)

    apply_full = _safe_preconditioner(_apply_full_unchecked)
    setattr(apply_full, "_sfincs_jax_structured_fblock_metadata", metadata)

    if reduce_full is None or expand_reduced is None:
        return apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    setattr(_apply_reduced, "_sfincs_jax_structured_fblock_metadata", metadata)
    return _apply_reduced


def _build_rhsmode1_structured_fblock_fp_radial_jacobi_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build a guarded FP-aware species/radial grouped preconditioner.

    The full-Fokker-Planck collision operator is dense in species and radial
    ``x`` for each fixed Legendre index and angular point.  This factor groups
    those non-contiguous blocks directly from the structured block-COO operator,
    capturing the missing FP coupling without a global sparse factor.
    """

    if getattr(op.fblock, "fp", None) is None and getattr(op.fblock, "fp_phi1", None) is None:
        raise NotImplementedError("structured f-block FP-radial preconditioner requires an FP collision term")

    n_species = int(op.n_species)
    n_x = int(op.n_x)
    n_xi = int(op.n_xi)
    n_theta = int(op.n_theta)
    n_zeta = int(op.n_zeta)
    blocks_per_group = n_species * n_x
    scalar_block_size = blocks_per_group * n_zeta
    n_groups = n_xi * n_theta
    max_block_size = _rhs1_int_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_FP_RADIAL_MAX_BLOCK_SIZE",
        default=2500,
        minimum=1,
    )
    if int(scalar_block_size) > int(max_block_size):
        raise MemoryError(
            "structured f-block FP-radial preconditioner block too large: "
            f"{int(scalar_block_size)} > {int(max_block_size)}; raise "
            "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_FP_RADIAL_MAX_BLOCK_SIZE to override"
        )

    estimated_factor_nbytes = int(n_groups * scalar_block_size * scalar_block_size * np.dtype(np.float64).itemsize)
    max_factor_nbytes = _rhs1_int_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_FP_RADIAL_MAX_FACTOR_NBYTES",
        default=256 * 1024 * 1024,
        minimum=1,
    )
    if estimated_factor_nbytes > int(max_factor_nbytes):
        raise MemoryError(
            "structured f-block FP-radial preconditioner factor too large: "
            f"{estimated_factor_nbytes} > {int(max_factor_nbytes)} bytes; raise "
            "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_FP_RADIAL_MAX_FACTOR_NBYTES to override"
        )

    regularization = _rhs1_float_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_FP_RADIAL_JACOBI_REG",
        default=1.0e-10,
        minimum=0.0,
    )
    damping = _rhs1_float_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_FP_RADIAL_JACOBI_DAMPING",
        default=1.0,
        minimum=0.0,
    )
    cache_key = _rhsmode1_structured_fblock_cache_key(
        op,
        "fp_radial_jacobi",
        params=(
            int(max_block_size),
            int(max_factor_nbytes),
            float(regularization),
            float(damping),
        ),
    )
    cached = _RHSMODE1_STRUCTURED_FBLOCK_PRECOND_CACHE.get(cache_key)
    cache_hit = cached is not None
    if cached is None:
        phi1_base = op.phi1_hat_base if getattr(op.fblock, "fp_phi1", None) is not None else None
        selection = select_structured_rhs1_fblock_operator(op.fblock, phi1_hat_base=phi1_base)
        if not bool(selection.selected):
            raise NotImplementedError(f"structured f-block FP-radial preconditioner unavailable: {selection.reason}")

        groups = np.empty((n_groups, blocks_per_group), dtype=np.int32)
        group_id = 0
        for ell in range(n_xi):
            for theta in range(n_theta):
                offset = 0
                for species in range(n_species):
                    for x_index in range(n_x):
                        groups[group_id, offset] = (((species * n_x + x_index) * n_xi + ell) * n_theta + theta)
                        offset += 1
                group_id += 1

        factor = selection.assembly.operator.grouped_jacobi_factor(
            block_groups=groups,
            regularization=float(regularization),
            damping=float(damping),
        )
        metadata = selection.to_dict()
        metadata["factor"] = factor.to_dict()
        metadata["regularization"] = float(regularization)
        metadata["damping"] = float(damping)
        metadata["line_kind"] = "fixed_l_theta_species_x_zeta"
        metadata["blocks_per_group"] = int(blocks_per_group)
        metadata["n_groups"] = int(n_groups)
        metadata["scalar_block_size"] = int(scalar_block_size)
        metadata["max_block_size"] = int(max_block_size)
        metadata["estimated_factor_nbytes"] = int(estimated_factor_nbytes)
        metadata["max_factor_nbytes"] = int(max_factor_nbytes)
        cached = _RHSMode1StructuredFBlockPrecondCache(
            operator=selection.assembly.operator,
            factor=factor,
            metadata=metadata,
        )
        _RHSMODE1_STRUCTURED_FBLOCK_PRECOND_CACHE[cache_key] = cached
    if cached.factor is None:
        raise RuntimeError("structured f-block FP-radial cache is missing factor")
    factor = cached.factor
    metadata = dict(cached.metadata)
    metadata["cache_hit"] = bool(cache_hit)

    f_size = int(op.f_size)

    def _apply_full_unchecked(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=jnp.float64)
        z_f = factor.apply(r_full[:f_size])
        return jnp.concatenate([z_f, r_full[f_size:]], axis=0)

    apply_full = _safe_preconditioner(_apply_full_unchecked)
    setattr(apply_full, "_sfincs_jax_structured_fblock_metadata", metadata)

    if reduce_full is None or expand_reduced is None:
        return apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    setattr(_apply_reduced, "_sfincs_jax_structured_fblock_metadata", metadata)
    return _apply_reduced


def _build_rhsmode1_structured_fblock_fp_lowmode_schur_preconditioner(
    *,
    op: V3FullSystemOperator,
    reduce_full: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
    expand_reduced: Callable[[jnp.ndarray], jnp.ndarray] | None = None,
) -> Callable[[jnp.ndarray], jnp.ndarray]:
    """Build an explicit FP-radial plus low-angular Galerkin correction."""

    if getattr(op.fblock, "fp", None) is None and getattr(op.fblock, "fp_phi1", None) is None:
        raise NotImplementedError("structured f-block FP low-mode Schur preconditioner requires an FP collision term")

    theta_modes = _rhs1_int_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_FP_LOWMODE_THETA",
        default=1,
        minimum=0,
    )
    zeta_modes = _rhs1_int_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_FP_LOWMODE_ZETA",
        default=1,
        minimum=0,
    )
    max_coarse_size = _rhs1_int_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_FP_LOWMODE_MAX_COARSE",
        default=800,
        minimum=1,
    )
    max_basis_nbytes = _rhs1_int_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_FP_LOWMODE_MAX_BASIS_NBYTES",
        default=128 * 1024 * 1024,
        minimum=1,
    )
    basis_batch_size = _rhs1_int_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_FP_LOWMODE_BASIS_BATCH",
        default=32,
        minimum=1,
    )
    regularization = _rhs1_float_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_FP_LOWMODE_SCHUR_REG",
        default=1.0e-10,
        minimum=0.0,
    )
    damping = _rhs1_float_env(
        "SFINCS_JAX_RHSMODE1_STRUCTURED_FBLOCK_FP_LOWMODE_SCHUR_DAMPING",
        default=1.0,
        minimum=0.0,
    )
    cache_key = _rhsmode1_structured_fblock_cache_key(
        op,
        "fp_lowmode_schur",
        params=(
            int(theta_modes),
            int(zeta_modes),
            int(max_coarse_size),
            int(max_basis_nbytes),
            int(basis_batch_size),
            float(regularization),
            float(damping),
        ),
    )
    cached = _RHSMODE1_STRUCTURED_FBLOCK_PRECOND_CACHE.get(cache_key)
    cache_hit = cached is not None
    if cached is None:
        base_preconditioner = _build_rhsmode1_structured_fblock_fp_radial_jacobi_preconditioner(op=op)
        base_metadata = getattr(base_preconditioner, "_sfincs_jax_structured_fblock_metadata", {})
        phi1_base = op.phi1_hat_base if getattr(op.fblock, "fp_phi1", None) is not None else None
        selection = select_structured_rhs1_fblock_operator(op.fblock, phi1_hat_base=phi1_base)
        if not bool(selection.selected):
            raise NotImplementedError(
                f"structured f-block FP low-mode Schur preconditioner unavailable: {selection.reason}"
            )
        coarse, feature_metadata = _build_rhs1_lowmode_angular_matrix_free_correction(
            op=op,
            operator=selection.assembly.operator,
            theta_modes=int(theta_modes),
            zeta_modes=int(zeta_modes),
            max_coarse_size=int(max_coarse_size),
            max_basis_batch_nbytes=int(max_basis_nbytes),
            basis_batch_size=int(basis_batch_size),
            regularization=float(regularization),
            damping=float(damping),
        )
        metadata = selection.to_dict()
        metadata["base_preconditioner"] = base_metadata
        metadata["coarse"] = coarse.to_dict()
        metadata["coarse_feature_selection"] = feature_metadata
        metadata["line_kind"] = "fp_radial_plus_low_angular_galerkin"
        metadata["theta_modes"] = int(theta_modes)
        metadata["zeta_modes"] = int(zeta_modes)
        metadata["max_coarse_size"] = int(max_coarse_size)
        metadata["max_basis_batch_nbytes"] = int(max_basis_nbytes)
        metadata["basis_batch_size"] = int(basis_batch_size)
        metadata["regularization"] = float(regularization)
        metadata["damping"] = float(damping)
        cached = _RHSMode1StructuredFBlockPrecondCache(
            operator=selection.assembly.operator,
            coarse=coarse,
            base_preconditioner=base_preconditioner,
            metadata=metadata,
        )
        _RHSMODE1_STRUCTURED_FBLOCK_PRECOND_CACHE[cache_key] = cached
    if cached.base_preconditioner is None or cached.coarse is None:
        raise RuntimeError("structured f-block FP low-mode cache is incomplete")
    base_preconditioner = cached.base_preconditioner
    coarse = cached.coarse
    operator = cached.operator
    metadata = dict(cached.metadata)
    metadata["cache_hit"] = bool(cache_hit)

    f_size = int(op.f_size)

    def _apply_full_unchecked(r_full: jnp.ndarray) -> jnp.ndarray:
        r_full = jnp.asarray(r_full, dtype=jnp.float64)
        z0_full = base_preconditioner(r_full)
        residual_f = r_full[:f_size] - operator.matvec(z0_full[:f_size])
        z_f = z0_full[:f_size] + coarse.apply(residual_f)
        return jnp.concatenate([z_f, z0_full[f_size:]], axis=0)

    apply_full = _safe_preconditioner(_apply_full_unchecked)
    setattr(apply_full, "_sfincs_jax_structured_fblock_metadata", metadata)

    if reduce_full is None or expand_reduced is None:
        return apply_full

    def _apply_reduced(r_reduced: jnp.ndarray) -> jnp.ndarray:
        z_full = apply_full(expand_reduced(r_reduced))
        return reduce_full(z_full)

    setattr(_apply_reduced, "_sfincs_jax_structured_fblock_metadata", metadata)
    return _apply_reduced


